// 知愛家教育機構 - 一次性資料匯入腳本
// 執行完畢後請刪除此檔案，並將 Start Command 改回 pnpm start

import mysql from 'mysql2/promise';
import 'dotenv/config';

const DB_URL = process.env.DATABASE_URL;
if (!DB_URL) {
  console.error('❌ DATABASE_URL 未設定');
  process.exit(1);
}

function parseUrl(url) {
  const m = url.match(/mysql:\/\/([^:]+):([^@]+)@([^:]+):(\d+)\/(.+)/);
  if (!m) throw new Error('無法解析 DATABASE_URL: ' + url);
  return { user: m[1], password: m[2], host: m[3], port: parseInt(m[4]), database: m[5] };
}

async function insertBatch(conn, sql, rows, batchSize = 100) {
  let count = 0;
  for (let i = 0; i < rows.length; i += batchSize) {
    const batch = rows.slice(i, i + batchSize);
    for (const row of batch) {
      try {
        await conn.execute(sql, Object.values(row));
        count++;
      } catch(e) {
        console.warn(`  跳過重複/錯誤資料:`, e.message.substring(0, 80));
      }
    }
    process.stdout.write(`  進度: ${i + batch.length}/${rows.length}\r`);
  }
  console.log(`  ✅ 完成 ${count} 筆`);
}

