const PARENT_COMM = [{"id": 30001, "weekNumber": 9, "date": "2026-02-26", "studentId": 27, "studentName": "謝知愛", "method": "phone", "teacherShare": "好棒棒，但是屁股很紅，請媽媽要特別注意他的屁股喔", "parentFeedback": "媽媽說好再麻煩老師幫忙協助擦屁屁膏，如果家長忘記帶的話要特別提醒家長喔，如果尿布沒有帶的時候要特別的再提醒家長兩次", "createdBy": 1}, {"id": 60001, "weekNumber": 9, "date": "2026-02-26", "studentId": 19, "studentName": "林冠邦", "method": "phone", "teacherShare": "練習扶站情形，我們會持續追蹤。目前扶站得很好，真的扶站得很好，之後會持續追蹤。", "parentFeedback": "了解。媽媽說在家裡面也都復健得很好，我們也會持續努力。謝謝老師的幫忙！", "createdBy": 1}, {"id": 90001, "weekNumber": 9, "date": "2026-03-01", "studentId": 19, "studentName": "林冠邦", "method": "phone", "teacherShare": "棒棒", "parentFeedback": "棒棒", "createdBy": 1}, {"id": 120001, "weekNumber": 10, "date": "2026-03-02", "studentId": 11, "studentName": "葉紫婕", "method": "interview", "teacherShare": "紫婕和同學互動關係緊密，也很樂於安慰同學", "parentFeedback": "在家中也是活動力十足，會安撫同學很可愛", "createdBy": 1590028}, {"id": 120002, "weekNumber": 10, "date": "2026-03-02", "studentId": 12, "studentName": "陳奕睿", "method": "interview", "teacherShare": "觀察連假回學校後的情緒反應，目前都狀況良好", "parentFeedback": "在家中偶爾遇到不順心的事會有小情緒，持續觀察與老師分享", "createdBy": 1590028}, {"id": 120003, "weekNumber": 10, "date": "2026-03-02", "studentId": 13, "studentName": "許睿桓", "method": "interview", "teacherShare": "在學校會主動和老師講話了！和朋友之間的互動也越來越頻繁", "parentFeedback": "和哥哥互動時也越來越好，也確實越來越願意開口發音，用手指著想表達的事", "createdBy": 1590028}, {"id": 150001, "weekNumber": 10, "date": "2026-03-02", "studentId": 14, "studentName": "蘇彥澄", "method": "interview", "teacherShare": "彥澄對指令的執行力越來越多，但情緒上也是來得快去得也快", "parentFeedback": "在家中也是情緒會突然爆發，但安撫下可以很快平復，對指令的理解真的有進步很多", "createdBy": 1590028}, {"id": 150002, "weekNumber": 10, "date": "2026-03-02", "studentId": 15, "studentName": "李澪", "method": "interview", "teacherShare": "李澪和同學的相處有越來越好，情緒偶爾出現時也能讓老師抱抱安撫", "parentFeedback": "希望李澪能越來越融入大家喔", "createdBy": 1590028}, {"id": 150003, "weekNumber": 10, "date": "2026-03-02", "studentId": 16, "studentName": "余承澔", "method": "interview", "teacherShare": "承澔最近和同學相處上較容易發生搶玩具的事件和推擠，已經協助引導中", "parentFeedback": "在家中無其他小孩一起玩，較難發現這個情況，再麻煩老師協助引導", "createdBy": 1590028}, {"id": 150004, "weekNumber": 10, "date": "2026-03-02", "studentId": 17, "studentName": "陳禹澔", "method": "interview", "teacherShare": "禹澔的語句有越來越增加，且對指令的執行力也很好，進步很多", "parentFeedback": "在家中也都會教導禹澔聽指令，但最近比較調皮，也希望老師繼續引導喔", "createdBy": 1590028}, {"id": 150005, "weekNumber": 10, "date": "2026-03-02", "studentId": 18, "studentName": "彭翊宸", "method": "interview", "teacherShare": "翊宸食慾越來越好，吃飯時也能夠好好坐著吃飯，也慢慢學會等待吃飯呢", "parentFeedback": "看到翊宸學會等待很開心，也發現翊宸越來越跟同學的相處更緊密了", "createdBy": 1590028}, {"id": 150006, "weekNumber": 10, "date": "2026-03-02", "studentId": 19, "studentName": "林冠邦", "method": "interview", "teacherShare": "冠邦還在持續練習走路和放手獨自站立，但偶爾有點不想動想休息，持續追蹤", "parentFeedback": "在家中也都有努力練習走路，覺得有進步，但真的偶爾不太想動", "createdBy": 1590028}, {"id": 150007, "weekNumber": 10, "date": "2026-03-02", "studentId": 20, "studentName": "蔡禾悅", "method": "interview", "teacherShare": "出國去玩呦", "parentFeedback": "出國去玩呦日本行", "createdBy": 1590028}, {"id": 180001, "weekNumber": 10, "date": "2026-03-04", "studentId": 21, "studentName": "劉瑀彤", "method": "interview", "teacherShare": "這週開始，會將瑀彤的早點（副食品）調整為（麵包），訓練瑀彤的咀嚼能力與牙齒發展唷！", "parentFeedback": "好的，沒問題！謝謝老師", "createdBy": 1440078}, {"id": 180002, "weekNumber": 10, "date": "2026-03-04", "studentId": 22, "studentName": "張瑾馨", "method": "interview", "teacherShare": "這週開始，會將瑾馨的早點（副食品）調整為（麵包），訓練瑀彤的咀嚼能力與牙齒發展唷！", "parentFeedback": "Ok！她很喜歡吃麵包xd", "createdBy": 1440078}, {"id": 180003, "weekNumber": 10, "date": "2026-03-04", "studentId": 23, "studentName": "余硯宸", "method": "interview", "teacherShare": "這週開始，會將硯宸的早點（副食品）調整為（麵包），訓練硯宸的咀嚼能力與牙齒發展唷！", "parentFeedback": "硯宸只要是吃的，都會很開心！謝謝老師xd", "createdBy": 1440078}, {"id": 180004, "weekNumber": 10, "date": "2026-03-04", "studentId": 24, "studentName": "蔡雨彤", "method": "interview", "teacherShare": "這週開始，會將雨彤的早點（副食品）調整為（麵包），訓練雨彤的咀嚼能力與牙齒發展唷！", "parentFeedback": "Ok", "createdBy": 1440078}, {"id": 180005, "weekNumber": 10, "date": "2026-03-04", "studentId": 25, "studentName": "黃映澄", "method": "interview", "teacherShare": "這週開始，會將映澄的早點（副食品）調整為（麵包），訓練映澄的咀嚼能力與牙齒發展唷！", "parentFeedback": "好的，希望映澄不會排斥xd", "createdBy": 1440078}, {"id": 210001, "weekNumber": 10, "date": "2026-03-06", "studentId": 26, "studentName": "林逸宸", "method": "interview", "teacherShare": "以往逸宸的餐兜都是每天帶回，現在更改為每週五帶回", "parentFeedback": "好的", "createdBy": 1440078}, {"id": 210002, "weekNumber": 10, "date": "2026-03-06", "studentId": 28, "studentName": "陳品叡", "method": "interview", "teacherShare": "以往可樂的餐兜都是每天帶回，現在更改為每週五帶回", "parentFeedback": "好的", "createdBy": 1440078}, {"id": 210003, "weekNumber": 10, "date": "2026-03-06", "studentId": 29, "studentName": "林禹順", "method": "interview", "teacherShare": "以往順順的餐兜都是每天帶回，現在更改為每週五帶回", "parentFeedback": "好的", "createdBy": 1440078}, {"id": 210004, "weekNumber": 10, "date": "2026-03-06", "studentId": 35, "studentName": "賴時儀", "method": "interview", "teacherShare": "這週時儀適應的還不錯唷，早上還有點想睡，但看到同學在玩玩具，開心的湊過去跟同學一起玩，好可愛喔！", "parentFeedback": "謝謝老師", "createdBy": 1440078}, {"id": 240001, "weekNumber": 10, "date": "2026-03-06", "studentId": 31, "studentName": "徐瑀彤", "method": "interview", "teacherShare": "瑀彤的發展篩檢表單，再麻煩爸爸媽媽幫老師填寫完成唷，謝謝！", "parentFeedback": "好的", "createdBy": 1440078}, {"id": 270001, "weekNumber": 10, "date": "2026-03-06", "studentId": 1, "studentName": "林品逸", "method": "interview", "teacherShare": "品逸現在非常有個性呢，有時還會直接尖叫，老師會慢慢地和他溝通的！", "parentFeedback": "品逸越來越有個性了，有時候都講不聽，再麻煩老師多多和他溝通了！", "createdBy": 390021}, {"id": 270002, "weekNumber": 10, "date": "2026-03-06", "studentId": 2, "studentName": "洪明樂", "method": "interview", "teacherShare": "明樂最近越來越愛說話了呢，會一直和老師同學聊天聊不停呢！", "parentFeedback": "明樂在家裡也是，都會跟爸爸媽媽聊天聊到不想睡覺～", "createdBy": 390021}, {"id": 270003, "weekNumber": 10, "date": "2026-03-06", "studentId": 3, "studentName": "張蘊桐", "method": "interview", "teacherShare": "蘊桐的表達能力越來越好了，但也越來越有個性，有時會不願意分享玩具，但在老師和她溝通過後，她就願意分享囉！非常棒呢！", "parentFeedback": "蘊桐在家裡也是，越來越有個性，再麻煩老師多多教導她了！", "createdBy": 390021}, {"id": 270004, "weekNumber": 10, "date": "2026-03-06", "studentId": 4, "studentName": "李芊樂", "method": "interview", "teacherShare": "芊樂這幾天在學校都有便便喔！超棒的！", "parentFeedback": "非常好！繼續保持！", "createdBy": 390021}, {"id": 270005, "weekNumber": 10, "date": "2026-03-06", "studentId": 5, "studentName": "黃予希", "method": "interview", "teacherShare": "予希挑食的狀況有改善囉，願意吃菜菜了！", "parentFeedback": "太好了，感謝老師！", "createdBy": 390021}, {"id": 270006, "weekNumber": 10, "date": "2026-03-06", "studentId": 6, "studentName": "吳允希", "method": "interview", "teacherShare": "允希在學校都活力滿滿的，是個活潑的孩子呢！", "parentFeedback": "允希在家裡也是，每天都活力滿滿！", "createdBy": 390021}, {"id": 270007, "weekNumber": 10, "date": "2026-03-03", "studentId": 7, "studentName": "楊曜任", "method": "interview", "teacherShare": "曜任現在對於自己想玩的玩具會非常積極的去爭取，有時候就會發生搶玩具的狀況，老師會在和他多多溝通！", "parentFeedback": "曜任在家裡也是，不過有姐姐在他不敢去跟姐姐搶玩具！", "createdBy": 390021}, {"id": 270008, "weekNumber": 10, "date": "2026-03-06", "studentId": 8, "studentName": "莊又羽", "method": "interview", "teacherShare": "又羽現在對於自己想要的東西會很明確的給出反應呢！", "parentFeedback": "又羽在家裡也是，但有時候不給他他就會生氣！", "createdBy": 390021}, {"id": 270009, "weekNumber": 10, "date": "2026-03-06", "studentId": 9, "studentName": "王鈺棠", "method": "interview", "teacherShare": "鈺棠是個很有規矩的小孩呢，從椅子上起來後都會默默的把椅子推回桌子下～～", "parentFeedback": "真棒，希望在家裡也可以這樣～～", "createdBy": 390021}, {"id": 270010, "weekNumber": 10, "date": "2026-03-06", "studentId": 10, "studentName": "吳承諺", "method": "interview", "teacherShare": "諺諺蠻適應大寶班的呦！也能和哥哥姐姐一起玩，很棒呢！", "parentFeedback": "太棒了！謝謝老師的用心！", "createdBy": 390021}, {"id": 300001, "weekNumber": 10, "date": "2026-03-05", "studentId": 30, "studentName": "陳杏恩", "method": "interview", "teacherShare": "杏恩今日精神活力都不錯！有流鼻涕情形，午休咳嗽一次醒來馬上便便，便量多有沾到床單。", "parentFeedback": "好的，昨晚凌晨也有咳到吐。", "createdBy": 750001}, {"id": 300002, "weekNumber": 10, "date": "2026-03-04", "studentId": 32, "studentName": "吳允霏", "method": "interview", "teacherShare": "今天大便3次；在教室常常說阿瑪阿瑪。", "parentFeedback": "他有時一天大多次，回家後也很喜歡說阿瑪阿瑪。", "createdBy": 750001}, {"id": 300003, "weekNumber": 10, "date": "2026-03-03", "studentId": 33, "studentName": "黃語則", "method": "interview", "teacherShare": "今天讓則則練習抬頭，抬得不錯！胯下兩側比較紅，有幫他勤換尿布。", "parentFeedback": "好的，他頭抬得越來越好；請老師奶量泡160cc。", "createdBy": 750001}, {"id": 300004, "weekNumber": 10, "date": "2026-03-06", "studentId": 30001, "studentName": "黃梓芸", "method": "interview", "teacherShare": "今日沒帶寶乖亞；有幫他吸鼻涕，吸鼻器卡鼻屎，因為沒有專屬清潔用具，僅清水沖洗，再麻煩媽咪處理；活動時寶貝太開心參與，手揮到眼睛旁邊有小抓痕。", "parentFeedback": "謝謝老師，他在家有時玩一玩，也會抓到自己臉，沒關係。", "createdBy": 750001}, {"id": 300005, "weekNumber": 10, "date": "2026-03-03", "studentId": 34, "studentName": "張語恩", "method": "interview", "teacherShare": "今日喝奶速度很快！有兩餐也都喝光100cc；在中心時有觀察到鼻塞情形。", "parentFeedback": "他有時喝得很快！有時喝很慢！謝謝老師。", "createdBy": 750001}, {"id": 330001, "weekNumber": 11, "date": "2026-03-09", "studentId": 11, "studentName": "葉紫婕", "method": "interview", "teacherShare": "紫婕繪畫時使用直式蠟筆叫不熟練，努力練習中", "parentFeedback": "在家中會嘗試改成直式蠟筆畫畫，再持續觀察", "createdBy": 1590028}, {"id": 330002, "weekNumber": 11, "date": "2026-03-09", "studentId": 12, "studentName": "陳奕睿", "method": "interview", "teacherShare": "奕睿現在會表達自己的需求，大約可講出五個字的句子", "parentFeedback": "在家中也很樂於跟爸媽講話，奕睿也很喜歡表達自己的需求", "createdBy": 1590028}, {"id": 330003, "weekNumber": 11, "date": "2026-03-09", "studentId": 13, "studentName": "許睿桓", "method": "interview", "teacherShare": "睿桓最近開始較會發出更多的聲音，而且也更願意跟班上同學一起互動而不是一個人自己玩了呦", "parentFeedback": "在家中也更願意開口跟爸媽表達，雖然還沒辦法講出完整的詞彙，但是已經很進步囉", "createdBy": 1590028}, {"id": 360001, "weekNumber": 11, "date": "2026-03-09", "studentId": 30, "studentName": "陳杏恩", "method": "phone", "teacherShare": "杏恩身體狀況還好嗎？他在中心活動時精神活力都不錯，只有午休躺平會微咳，請問他明天會回來上課嗎？", "parentFeedback": "他身體狀況跟上周差不多，躺平睡覺會咳嗽，今天家裡有事，所以請假，明天就會返校上課。", "createdBy": 750001}, {"id": 390001, "weekNumber": 11, "date": "2026-03-10", "studentId": 14, "studentName": "蘇彥澄", "method": "interview", "teacherShare": "彥澄在中心可以獨自完成指令任務，且會主動說抱抱擁抱同學", "parentFeedback": "在家中和哥哥互動也是很密切，個性外向真的很可愛", "createdBy": 1590028}, {"id": 390002, "weekNumber": 11, "date": "2026-03-10", "studentId": 15, "studentName": "李澪", "method": "interview", "teacherShare": "李澪雖然早上還是會有小情緒，但活動進行時可自行探索教具", "parentFeedback": "在家中很喜歡玩教具，聽音樂跳舞呢", "createdBy": 1590028}, {"id": 390003, "weekNumber": 11, "date": "2026-03-10", "studentId": 16, "studentName": "余承澔", "method": "interview", "teacherShare": "早上活動力很好，午休也正常入睡", "parentFeedback": "原本擔心太早起床會有情緒不穩，還好沒有影響上課", "createdBy": 1590028}, {"id": 390004, "weekNumber": 11, "date": "2026-03-10", "studentId": 17, "studentName": "陳禹澔", "method": "interview", "teacherShare": "禹澔近日較獨立自主喔，進步很多！", "parentFeedback": "慢慢長大了呢！很棒！在家中也很樂於探索新事物", "createdBy": 1590028}, {"id": 390005, "weekNumber": 11, "date": "2026-03-10", "studentId": 18, "studentName": "彭翊宸", "method": "interview", "teacherShare": "翊宸在中心鼻涕多，顏色為綠色，性質稠", "parentFeedback": "持續觀察，有咳嗽情形再協助告知", "createdBy": 1590028}, {"id": 390006, "weekNumber": 11, "date": "2026-03-10", "studentId": 19, "studentName": "林冠邦", "method": "interview", "teacherShare": "冠邦在中心呼吸時有痰音，偶爾小咳嗽，鼻水少", "parentFeedback": "持續觀察感冒情形，注意體溫", "createdBy": 1590028}, {"id": 390007, "weekNumber": 11, "date": "2026-03-10", "studentId": 20, "studentName": "蔡禾悅", "method": "interview", "teacherShare": "禾悅出國回來中心上課的情緒還算可以安撫，中午也有好好休息睡覺，吃飯吃得很好呢", "parentFeedback": "太好了！原本很擔心情緒問題，持續加油", "createdBy": 1590028}, {"id": 420001, "weekNumber": 11, "date": "2026-03-13", "studentId": 32, "studentName": "吳允霏", "method": "interview", "teacherShare": "今日喝奶速度和量都比之前進步！喝到180 cc；背心的扣子有脫落，放在書包前面那格。", "parentFeedback": "謝謝老師；奶粉空罐要帶回家。", "createdBy": 750001}, {"id": 420002, "weekNumber": 11, "date": "2026-03-13", "studentId": 30001, "studentName": "黃梓芸", "method": "phone", "teacherShare": "媽咪，想跟您確認寶貝上次的服藥時間？您寫7：20喝奶，餵藥單上有勾早餐後餵藥；梓芸最近趴著時頭抬得越來越好！", "parentFeedback": "他早上喝奶完馬上睡著，今早還沒吃藥，現在可以餵；他的奶粉空罐要帶回家。", "createdBy": 750001}, {"id": 420003, "weekNumber": 11, "date": "2026-03-14", "studentId": 21, "studentName": "劉瑀彤", "method": "interview", "teacherShare": "早餐調整為麵包後，瑀彤吃得很好，一塊接著一塊，而且還不忘要記得喝水，超棒", "parentFeedback": "在家也會這樣xd", "createdBy": 1440078}, {"id": 420004, "weekNumber": 11, "date": "2026-03-14", "studentId": 22, "studentName": "張瑾馨", "method": "interview", "teacherShare": "早餐調整為麵包後，瑾馨吃得很好，一塊接著一塊，而且還不忘要記得喝水，超棒", "parentFeedback": "謝謝老師", "createdBy": 1440078}, {"id": 420005, "weekNumber": 11, "date": "2026-03-14", "studentId": 23, "studentName": "余硯宸", "method": "interview", "teacherShare": "早餐調整為麵包後，硯宸吃得很好，一塊接著一塊，而且還不忘要記得喝水，超棒", "parentFeedback": "不挑食的乖寶寶", "createdBy": 1440078}, {"id": 420006, "weekNumber": 11, "date": "2026-03-14", "studentId": 24, "studentName": "蔡雨彤", "method": "interview", "teacherShare": "早餐調整為麵包後，雨彤吃得很好，一塊接著一塊，而且還不忘要記得喝水，超棒", "parentFeedback": "Ok", "createdBy": 1440078}, {"id": 420007, "weekNumber": 11, "date": "2026-03-14", "studentId": 25, "studentName": "黃映澄", "method": "interview", "teacherShare": "早餐調整為麵包後，澄澄吃得很好，一塊接著一塊，而且還不忘要記得喝水，超棒", "parentFeedback": "謝謝老師", "createdBy": 1440078}, {"id": 420008, "weekNumber": 11, "date": "2026-03-14", "studentId": 34, "studentName": "張語恩", "method": "interview", "teacherShare": "今天帶著語恩認識水中動物，對於紅色螃蟹的圖片特別有反應，會發出聲音。", "parentFeedback": "呵呵！家中有類似的紅色龍蝦奶嘴，他可能想跟老師分享什麼。睡覺時，請老師拆掉口水巾。", "createdBy": 750001}, {"id": 420009, "weekNumber": 11, "date": "2026-03-14", "studentId": 35, "studentName": "賴時儀", "method": "interview", "teacherShare": "還在適應環境的時儀，食慾跟睡眠都還不錯，跟同學互動時會默默的觀察，嘴角微微一笑的時候好可愛", "parentFeedback": "再麻煩老師多擔待了，謝謝老師", "createdBy": 1440078}, {"id": 420010, "weekNumber": 11, "date": "2026-03-14", "studentId": 26, "studentName": "林逸宸", "method": "interview", "teacherShare": "哇！逸宸副食品越吃越有感謝喔，每餐都一口接著一口，下週將滿一歲囉！老師會慢慢將逸宸的三餐調整為副食品，讓他吃飽飽，開開心心上學唷", "parentFeedback": "很棒，希望可以乖乖聽話，不造成老師麻煩，辛苦囉", "createdBy": 1440078}, {"id": 420011, "weekNumber": 11, "date": "2026-03-14", "studentId": 33, "studentName": "黃語則", "method": "interview", "teacherShare": "則則整體都蠻穩定，體驗教具情緒都很淡定，今日睡覺稍微較容易醒。", "parentFeedback": "謝謝，醫師建議語則在中心奶量改成三小時餵一次，每次150cc。", "createdBy": 750001}, {"id": 420012, "weekNumber": 11, "date": "2026-03-14", "studentId": 28, "studentName": "陳品叡", "method": "interview", "teacherShare": "最近可樂在吃飯的時候會東張西望，老師引導他後，有乖乖聽話，一口接一口，可愛的小手還會揮舞著，好有趣呀", "parentFeedback": "在家有時也會這樣子xd", "createdBy": 1440078}, {"id": 420013, "weekNumber": 11, "date": "2026-03-14", "studentId": 29, "studentName": "林禹順", "method": "interview", "teacherShare": "順順這兩天睡前的情緒有點不穩，老師讓他吃奶嘴哄睡後，呆萌呆萌的看著老師幾秒後，慢慢斷電，實在太有趣了啦", "parentFeedback": "順順真是個戲劇化百出的寶寶xd", "createdBy": 1440078}, {"id": 420014, "weekNumber": 11, "date": "2026-03-14", "studentId": 31, "studentName": "徐瑀彤", "method": "interview", "teacherShare": "瑀彤最近會在飯前跟飯後時，一直想睡，老師在飯前有先讓他休息一下後再叫她起來吃飯，吃飽沒多久，瑀彤又斷電了！很好睡xd", "parentFeedback": "有這麼累嗎xd", "createdBy": 1440078}, {"id": 450001, "weekNumber": 12, "date": "2026-03-17", "studentId": 33, "studentName": "黃語則", "method": "interview", "teacherShare": "今日排便多次，便便狀況是正常無異樣；趴著時會一直排氣。", "parentFeedback": "謝謝老師照顧，他每天在中心第一餐奶前要餵寶乖亞，回家時也是一直噗噗放屁。", "createdBy": 750001}, {"id": 450002, "weekNumber": 12, "date": "2026-03-20", "studentId": 30001, "studentName": "黃梓芸", "method": "interview", "teacherShare": "回家前有便便在肛門口，已馬上幫他換尿布，肛門口有輕微紅屁屁，家長下週可以讓寶貝帶屁屁膏來。", "parentFeedback": "好的，謝謝！他有時假日在家每餐幾乎都只喝70cc，但是也有大便;平日的話，就可以恢復正常奶量一百多cc", "createdBy": 750001}, {"id": 450003, "weekNumber": 12, "date": "2026-03-19", "studentId": 30, "studentName": "陳杏恩", "method": "interview", "teacherShare": "杏恩入中心後，能自己獨立玩教具，心情很好笑咪咪看著老師，也會想找同學，會主動拿玩具給同學。", "parentFeedback": "現在杏恩上學時入中心會主動伸手給老師抱，越來越喜歡老師和上學，謝謝老師！", "createdBy": 750001}, {"id": 450004, "weekNumber": 12, "date": "2026-03-18", "studentId": 32, "studentName": "吳允霏", "method": "interview", "teacherShare": "允霏左眼眼睛紅，再請媽媽留意，建議帶去眼科。最近扶站越來越不害怕，有進步！", "parentFeedback": "好的，不知道是不是過敏；在家裡最近也都會自己扶沙發嘗試站。", "createdBy": 750001}, {"id": 450005, "weekNumber": 12, "date": "2026-03-19", "studentId": 34, "studentName": "張語恩", "method": "interview", "teacherShare": "喝奶速度依舊很快，三餐也都喝得不錯，喝奶時會自己想扶奶瓶。", "parentFeedback": "謝謝老師；請老師回家前不要幫他黏包巾，因為他要坐汽座，可以蓋薄被即可。", "createdBy": 750001}, {"id": 480001, "weekNumber": 12, "date": "2026-03-20", "studentId": 21, "studentName": "劉瑀彤", "method": "interview", "teacherShare": "近期發現瑀彤越來越會說話，懂得表達自己，老師看了都有種莫名的感動♥️", "parentFeedback": "她有偶包啦，在家就都不一樣了😂", "createdBy": 1440078}, {"id": 480002, "weekNumber": 12, "date": "2026-03-20", "studentId": 22, "studentName": "張瑾馨", "method": "interview", "teacherShare": "近期有發現瑾馨跟同學玩的時候會不自覺地壓在同學身上，老師看到有立即制止與引導後，瑾馨改善許多", "parentFeedback": "謝謝老師，在家也會引導瑾馨", "createdBy": 1440078}, {"id": 480003, "weekNumber": 12, "date": "2026-03-20", "studentId": 23, "studentName": "余硯宸", "method": "interview", "teacherShare": "近日媽咪有提到硯宸O型腿的部分，在校活動期間老師有特別觀察與注意，有適時的引導硯宸兩腳伸直，硯宸很棒也很聰明，自己把兩腳伸直後，把玩具放在自己腳上玩，很棒😁", "parentFeedback": "謝謝老師，辛苦了", "createdBy": 1440078}, {"id": 480004, "weekNumber": 12, "date": "2026-03-20", "studentId": 24, "studentName": "蔡雨彤", "method": "interview", "teacherShare": "雨彤最近跟模仿同學把自己的被被丟在地上，老師看到後有立即制止，並引導她那是睡覺要蓋的，不能這樣丟地上哦！雨彤還會回答說好，太可愛了😂", "parentFeedback": "謝謝老師，在家若也有發生此行為的話，我們也會制止與引導的", "createdBy": 1440078}, {"id": 480005, "weekNumber": 12, "date": "2026-03-20", "studentId": 25, "studentName": "黃映澄", "method": "interview", "teacherShare": "澄澄最近很喜歡說話，但發音還不太清楚，有時會自己生氣哭哭，老師安撫引導後，澄澄會咿咿呀呀的回應，很有趣", "parentFeedback": "澄澄在家也是一直跟爸爸媽媽咿咿呀呀的說不停，雖然爸爸媽媽聽不太懂，但是還真的蠻有趣的xd", "createdBy": 1440078}, {"id": 480006, "weekNumber": 12, "date": "2026-03-20", "studentId": 35, "studentName": "賴時儀", "method": "interview", "teacherShare": "近期時儀有慢慢適應在校團體生活了唷，棒棒的！有時候聽到關鍵字會哭哭想媽媽，但老師安撫引導後，會對著老師微笑，開心的去跟同學玩玩具，好棒！持續進步中", "parentFeedback": "謝謝老師的照顧，時儀就麻煩老師多多擔待了，辛苦老師了", "createdBy": 1440078}, {"id": 480007, "weekNumber": 12, "date": "2026-03-20", "studentId": 26, "studentName": "林逸宸", "method": "interview", "teacherShare": "哇！逸宸滿週歲啦，歡呼歡呼~~~\n老師幫逸宸抓週的時候，逸宸每個都摸過一遍後，最終決定先拿起聽診器，大玩特玩一翻後，要老師抱抱回教室吃飯了，哈哈！很可愛.. 謝謝爸爸媽媽買蛋糕與老師同學們分享，好吃♥️♥️ 祝逸宸生日快樂，平安健康🥳🥳🥳", "parentFeedback": "謝謝老師對逸宸的照顧，往後的每一天還需要老師多多指教唷", "createdBy": 1440078}, {"id": 480008, "weekNumber": 12, "date": "2026-03-20", "studentId": 28, "studentName": "陳品叡", "method": "interview", "teacherShare": "近日老師發現可樂食慾大開，每每在餵可樂吃副食品的時候，真的是一口接一口欸，吃得相當開心，老師看了都要流口水了，呵呵！長大了♥️♥️♥️", "parentFeedback": "可樂在家有時也會這樣，喜歡吃美食😁😁", "createdBy": 1440078}, {"id": 480009, "weekNumber": 12, "date": "2026-03-20", "studentId": 29, "studentName": "林禹順", "method": "interview", "teacherShare": "順順最近很喜歡扶站喔，站著就不動了，持續了將近半分鐘後，看了老師一眼後，自己迅速的找同學玩，模樣相當可愛又有趣", "parentFeedback": "順順喜歡探索，觀察入微😁", "createdBy": 1440078}, {"id": 480010, "weekNumber": 12, "date": "2026-03-20", "studentId": 31, "studentName": "徐瑀彤", "method": "interview", "teacherShare": "瑀彤最近好喜歡笑哦，早上到中心就對著老師同學微笑，超可愛！老師與她互動的過程中，還會主動拿玩具分享給老師，很棒", "parentFeedback": "謝謝老師", "createdBy": 1440078}, {"id": 510001, "weekNumber": 12, "date": "2026-03-18", "studentId": 11, "studentName": "葉紫婕", "method": "interview", "teacherShare": "最近語言發展有比較進步，也較願意講詞彙努力學習中", "parentFeedback": "依照老師說的用歌唱的方式訓練語言發展有明顯進步也較願意講詞彙", "createdBy": 1590028}, {"id": 510002, "weekNumber": 12, "date": "2026-03-18", "studentId": 12, "studentName": "陳奕睿", "method": "interview", "teacherShare": "最近語言上已經可以講到五到六個字的句子，而且可以有結構式的講出正確的語句", "parentFeedback": "目前在家中也有持續加強訓練語言方面的句子，指令上的操作也有明顯的進步", "createdBy": 1590028}, {"id": 510003, "weekNumber": 12, "date": "2026-03-18", "studentId": 13, "studentName": "許睿桓", "method": "interview", "teacherShare": "本週出國遊玩", "parentFeedback": "本週出國遊玩", "createdBy": 1590028}, {"id": 510004, "weekNumber": 12, "date": "2026-03-18", "studentId": 14, "studentName": "蘇彥澄", "method": "interview", "teacherShare": "這週的語言發展有明顯進步，對於指令上的操作和模仿老師的動作，也也有明顯的進步很多", "parentFeedback": "目前在家中也有加強訓練與指令上的操作，對於陌生人接受度也很高", "createdBy": 1590028}, {"id": 510005, "weekNumber": 12, "date": "2026-03-18", "studentId": 15, "studentName": "李澪", "method": "interview", "teacherShare": "和班上同學的互動仍然在努力進行中，會依照家長的需求增加練習中文詞彙跟日常生活的語句練習", "parentFeedback": "在家裡較無法練習中文語句，因此在中心希望可以增加中文的語句練習", "createdBy": 1590028}, {"id": 510006, "weekNumber": 12, "date": "2026-03-18", "studentId": 16, "studentName": "余承澔", "method": "interview", "teacherShare": "目前可以模仿老師的所有動作，去做一個聯想的操作，老師也有增加語詞的訓練", "parentFeedback": "目前在家中有依照老師的建議，持續共讀時光，有明顯的進步", "createdBy": 1590028}, {"id": 510007, "weekNumber": 12, "date": "2026-03-18", "studentId": 17, "studentName": "陳禹澔", "method": "interview", "teacherShare": "這週進步很多，不管是情緒方面還是指令操作，甚至是自行探索都有多方面願意嘗試的動作", "parentFeedback": "情緒方面確實有穩定很多，在中心聽老師分享與在家裡會發生的情緒方面的問題相同，持續努力中", "createdBy": 1590028}, {"id": 510008, "weekNumber": 12, "date": "2026-03-18", "studentId": 18, "studentName": "彭翊宸", "method": "interview", "teacherShare": "老師觀察到指令上操作有明顯進步，用餐時間也比較能夠穩定坐在位置上", "parentFeedback": "在家裡也有感受到明顯的進步，最近在加強練習使用牙刷和洗手", "createdBy": 1590028}, {"id": 510009, "weekNumber": 12, "date": "2026-03-18", "studentId": 19, "studentName": "林冠邦", "method": "interview", "teacherShare": "這週有加強獨自走路的發展練習，有建議家長在家裡也可以持續加強，有明顯進步，目前可以獨自踏出步伐以右腳為先走了一步", "parentFeedback": "目前在家裡有依照老師的指示持續練習，最近也能夠穿鞋子走走路，持續練習中", "createdBy": 1590028}, {"id": 510010, "weekNumber": 12, "date": "2026-03-18", "studentId": 20, "studentName": "蔡禾悅", "method": "interview", "teacherShare": "偶爾還是會有情緒上的波動較明顯，但經過老師的安撫不用太久即可和班上同學相處熱絡", "parentFeedback": "在家裡有減少馬上哭哭就抱在懷裡的動作，改成會透過語言溝通慢慢讓小孩理解，持續努力讓情緒更穩定，但互動上和指令操作上有慢慢進步", "createdBy": 1590028}, {"id": 540001, "weekNumber": 13, "date": "2026-03-23", "studentId": 31, "studentName": "徐瑀彤", "method": "interview", "teacherShare": "今天幫瑀彤換尿布時，發現瑀彤屁屁裡面有一條很長的頭髮，老師將頭髮拉出來後有觀察瑀彤的身體狀況，一切良好，原本的紅屁屁也好很多，再麻煩家長多留意瑀彤在家時的狀況，謝謝！", "parentFeedback": "可能是在家的時候不小心把頭髮吃進肚子裡了，謝謝老師！爸爸媽媽會多留意", "createdBy": 1440078}, {"id": 540002, "weekNumber": 13, "date": "2026-03-23", "studentId": 28, "studentName": "陳品叡", "method": "interview", "teacherShare": "原本跟媽咪討論好，可樂在校的副食品3+奶1..\n\n目前可樂的奶粉將食用完，之後媽咪可以用1份（分裝式）的奶粉放進書包，方便攜帶", "parentFeedback": "好的，沒問題！謝謝老師", "createdBy": 1440078}, {"id": 570001, "weekNumber": 13, "date": "2026-03-25", "studentId": 21, "studentName": "劉瑀彤", "method": "interview", "teacherShare": "好的，沒有問題！老師也會多留意瑀彤屁屁的狀況，隨時與家長聯絡！", "parentFeedback": "瑀彤屁屁有紅疹，再麻煩老師幫忙勤換尿布，謝謝！", "createdBy": 1440078}, {"id": 570002, "weekNumber": 13, "date": "2026-03-25", "studentId": 25, "studentName": "黃映澄", "method": "interview", "teacherShare": "好的，沒有問題！老師會多留意，有問題會隨時與家長聯繫", "parentFeedback": "澄澄昨晚在家有發燒情況，有餵退燒藥！\n今天再麻煩老師多留意澄澄身體狀況，謝謝", "createdBy": 1440078}, {"id": 570003, "weekNumber": 13, "date": "2026-03-25", "studentId": 35, "studentName": "賴時儀", "method": "interview", "teacherShare": "好的，沒問題！媽咪辛苦了，老師會多關心時儀，並幫時儀塗抹屁屁膏", "parentFeedback": "這兩天因蚊子叮加紅屁屁，心情不佳！再請老師多費心了，有準備屁屁膏，再麻煩老師幫忙了，謝謝！", "createdBy": 1440078}, {"id": 600001, "weekNumber": 13, "date": "2026-03-27", "studentId": 22, "studentName": "張瑾馨", "method": "interview", "teacherShare": "最近跟瑾馨互動的過程中，有發現瑾馨進步很多，手眼協調的程度持續上升，表情動作也很豐富有趣，越大越活潑可愛😊😊", "parentFeedback": "謝謝老師，瑾馨在家根本就是小惡魔🤣", "createdBy": 1440078}, {"id": 630001, "weekNumber": 13, "date": "2026-03-27", "studentId": 23, "studentName": "余硯宸", "method": "interview", "teacherShare": "硯宸最近會用眼神表情來表達他想要的玩具，若沒有如願，會有點失落！經過老師安撫引導加互動後，硯宸很快就恢復了，開心的去玩😊", "parentFeedback": "謝謝老師，硯宸越大越有自己的想法xd", "createdBy": 1440078}, {"id": 630002, "weekNumber": 13, "date": "2026-03-27", "studentId": 24, "studentName": "蔡雨彤", "method": "interview", "teacherShare": "雨彤最近喜歡說話，會一直跟老師互動對話，尤其是在午休之前，雨彤會吃著奶嘴咿咿呀呀的跟自己對話，醞釀睡意，睡著後的模樣還真可愛呀❤️❤️", "parentFeedback": "雨彤在家也會這樣欸，有時候會因為沒有受到回應而生氣xd", "createdBy": 1440078}, {"id": 630003, "weekNumber": 13, "date": "2026-03-27", "studentId": 26, "studentName": "林逸宸", "method": "interview", "teacherShare": "逸宸副食品吃得越來越好欸，進步好多（灑花...\n越長大越可愛😊😊", "parentFeedback": "謝謝老師，他是個吃貨寶寶xd", "createdBy": 1440078}, {"id": 630004, "weekNumber": 13, "date": "2026-03-27", "studentId": 29, "studentName": "林禹順", "method": "interview", "teacherShare": "順順好棒呀，吃完午餐後，都不用奶嘴，自己拿著被被就可以安穩入睡，即便老師當下在忙，他也會靜靜的自己醞釀睡意後斷電，睡著的樣子超療癒唷❤️❤️", "parentFeedback": "哈哈，順順有吃飽就會很乖的自己玩，自己睡xd  謝謝老師", "createdBy": 1440078}, {"id": 660001, "weekNumber": 13, "date": "2026-03-25", "studentId": 30, "studentName": "陳杏恩", "method": "phone", "teacherShare": "杏恩還好嗎？明天會返校上課嗎？他昨天在中心睡得好、吃得好、活力也很好，午休躺平也沒咳嗽，很喜歡聽老師說故事。", "parentFeedback": "昨天回家晚上躺平也沒咳嗽，今天帶去剪髮，明天會去上課。原本故事書看幾頁就不看，自從去中心後，睡前會主動拿故事給爸爸媽媽，聽完一本會再拿下一本，愛聽故事的寶寶。", "createdBy": 750001}, {"id": 660002, "weekNumber": 13, "date": "2026-03-25", "studentId": 32, "studentName": "吳允霏", "method": "interview", "teacherShare": "有按時幫寶貝點眼藥水，有流鼻涕狀況，鼻涕偏黃，有幫寶貝吸鼻涕；喝奶速度及奶量今日都不錯！四點多有大少許便便，請留意可能會再上；請幫寶貝準備尿布一袋。", "parentFeedback": "好的，謝謝！在家也都黃鼻涕，感冒引起眼睛也紅紅。", "createdBy": 750001}, {"id": 660003, "weekNumber": 13, "date": "2026-03-25", "studentId": 33, "studentName": "黃語則", "method": "interview", "teacherShare": "則則今早初體驗白粥，起初願意開口、也有吞嚥，吃到中後段會開始稍微白粥吐出來，相信慢慢來他會越吃越好；吃了50ml白粥,仍有補奶90cc讓他喝，寶乖亞也有讓他在第一餐一起吃。", "parentFeedback": "希望則則副食品可以越吃越多，好期待看到他吃白粥的樣子，終於要開始吃人類吃的食物。", "createdBy": 750001}, {"id": 660004, "weekNumber": 13, "date": "2026-03-26", "studentId": 30001, "studentName": "黃梓芸", "method": "phone", "teacherShare": "梓芸書包內奶瓶少帶兩個，請問要讓他先用中心的備用的？還是？寶貝的污衣袋及枕頭書包內也沒看到。孩子的雙眼有點微紅，先告知您，我們會再留意。", "parentFeedback": "了解，兩個奶瓶及污衣袋晚點我會送過去中心；枕頭在另外的家，今天就不帶過去了。", "createdBy": 750001}, {"id": 660005, "weekNumber": 13, "date": "2026-03-26", "studentId": 34, "studentName": "張語恩", "method": "interview", "teacherShare": "孩子喝奶奶量增加到120ml,喝奶速度依舊很快，三餐都有喝完；睡眠很安穩；體驗兒童活動時情緒也都很穩定，很棒！", "parentFeedback": "謝謝老師", "createdBy": 750001}, {"id": 690001, "weekNumber": 13, "date": "2026-03-27", "studentId": 11, "studentName": "葉紫婕", "method": "interview", "teacherShare": "最近對動物的認知有進步，持續練習中", "parentFeedback": "在家中有持續練習包含生活日常的用品", "createdBy": 1590028}, {"id": 690002, "weekNumber": 13, "date": "2026-03-27", "studentId": 12, "studentName": "陳奕睿", "method": "interview", "teacherShare": "目前有引導想要換尿布時主動提出，目前正在努力練習中", "parentFeedback": "在家中也有引導換尿布時主動提出，目前都在持續進行中", "createdBy": 1590028}, {"id": 690003, "weekNumber": 13, "date": "2026-03-27", "studentId": 13, "studentName": "許睿桓", "method": "interview", "teacherShare": "最近會依照指令將老師指示的東西拿過去相對應的位置", "parentFeedback": "在家中也都有持續進行練習指令", "createdBy": 1590028}, {"id": 690004, "weekNumber": 13, "date": "2026-03-27", "studentId": 14, "studentName": "蘇彥澄", "method": "interview", "teacherShare": "目前對於模仿與具有進步，且會主動和老師討論看到的事物", "parentFeedback": "在家中都有持續進行引導，謝謝老師們的提議，目前活動也都會主動開口說詞彙", "createdBy": 1590028}, {"id": 690005, "weekNumber": 13, "date": "2026-03-27", "studentId": 15, "studentName": "李澪", "method": "interview", "teacherShare": "目前情緒有漸漸穩定，用餐方面飲食的量也有增加", "parentFeedback": "在家中也都會模仿學校的活動，給予音樂上和舞蹈上的學習", "createdBy": 1590028}, {"id": 690006, "weekNumber": 13, "date": "2026-03-27", "studentId": 16, "studentName": "余承澔", "method": "interview", "teacherShare": "目前有引導不不和同學爭搶玩具，會教小朋友輕輕放下，或是轉移注意力將其他教具代替", "parentFeedback": "目前觀察和其他小朋友一起貢丸教具時確實有搶搶的行為，會持續努力練習與引導", "createdBy": 1590028}, {"id": 690007, "weekNumber": 13, "date": "2026-03-27", "studentId": 17, "studentName": "陳禹澔", "method": "interview", "teacherShare": "在中心有流鼻水和咳嗽的情況，也都有持續觀察體溫的變化", "parentFeedback": "在家中也有感冒情況，已帶到醫師看診", "createdBy": 1590028}, {"id": 690008, "weekNumber": 13, "date": "2026-03-27", "studentId": 18, "studentName": "彭翊宸", "method": "interview", "teacherShare": "目前在中心會有搶同學玩具的情形發生，老師也都會在還原一次相對應的情況，且了解詳細的情形，偶爾發現是安撫同學時力道還不會拿捏", "parentFeedback": "在家中會有搶東西的行為，也觀察到會丟東西，會依照老師的建議給予引導", "createdBy": 1590028}, {"id": 690009, "weekNumber": 13, "date": "2026-03-27", "studentId": 19, "studentName": "林冠邦", "method": "interview", "teacherShare": "目前在中心已經會蹲下站起來，且次數越來越多，也能自己獨自向前走一到兩步", "parentFeedback": "在家裡也都有持續練習走路的情形，若有進展再與老師分享", "createdBy": 1590028}, {"id": 690010, "weekNumber": 13, "date": "2026-03-27", "studentId": 20, "studentName": "蔡禾悅", "method": "interview", "teacherShare": "目前在中心只要是繪畫或共讀方面的課程，都發現會比較有明顯的興趣和參與度的提升", "parentFeedback": "在家裡沒有試過讓小朋友畫畫，但是確實很愛看書，謝謝老師們的陪伴與引導", "createdBy": 1590028}, {"id": 720001, "weekNumber": 11, "date": "2026-03-14", "studentId": 1, "studentName": "林品逸", "method": "interview", "teacherShare": "品逸最近都很喜歡跟同學互動，只是力道會過大所以我們都會比較注意看著品逸和同學的相處模式", "parentFeedback": "好的，謝謝老師", "createdBy": 330019}, {"id": 720002, "weekNumber": 11, "date": "2026-03-14", "studentId": 2, "studentName": "洪明樂", "method": "interview", "teacherShare": "最近表現越來越棒，表達上也變的很清楚唷", "parentFeedback": "謝謝老師", "createdBy": 330019}, {"id": 720003, "weekNumber": 11, "date": "2026-03-14", "studentId": 3, "studentName": "張蘊桐", "method": "phone", "teacherShare": "最近都會和芋頭聊聊告訴她在家要對爸爸媽媽好一點，他們很辛苦", "parentFeedback": "感謝老師的幫忙", "createdBy": 330019}, {"id": 720004, "weekNumber": 11, "date": "2026-03-14", "studentId": 4, "studentName": "李芊樂", "method": "interview", "teacherShare": "最近早上心情都還不錯，表現的都很棒", "parentFeedback": "謝謝老師", "createdBy": 330019}, {"id": 720005, "weekNumber": 11, "date": "2026-03-14", "studentId": 5, "studentName": "黃予希", "method": "interview", "teacherShare": "這幾天的表現都很棒喔，吃好睡好", "parentFeedback": "謝謝老師", "createdBy": 330019}, {"id": 720006, "weekNumber": 11, "date": "2026-03-14", "studentId": 6, "studentName": "吳允希", "method": "interview", "teacherShare": "最近很喜歡和同學玩，也很會帶動大家呢", "parentFeedback": "謝謝老師，在家也都快抓不住了", "createdBy": 330019}, {"id": 720007, "weekNumber": 11, "date": "2026-03-14", "studentId": 7, "studentName": "楊曜任", "method": "interview", "teacherShare": "早上都不太愛吃麵包，看到大家都去玩就只吃一點點就去玩了～", "parentFeedback": "辛苦老師了", "createdBy": 330019}, {"id": 720008, "weekNumber": 11, "date": "2026-03-14", "studentId": 8, "studentName": "莊又羽", "method": "interview", "teacherShare": "最近很喜歡講話，而且表達的音都越來越清楚了呢", "parentFeedback": "謝謝老師", "createdBy": 330019}, {"id": 720009, "weekNumber": 11, "date": "2026-03-14", "studentId": 9, "studentName": "王鈺棠", "method": "interview", "teacherShare": "最近很喜歡跟同學玩，大家做什麼他就跟著做什麼呢", "parentFeedback": "越來越融入了真棒", "createdBy": 330019}, {"id": 720010, "weekNumber": 11, "date": "2026-03-14", "studentId": 10, "studentName": "吳承諺", "method": "interview", "teacherShare": "最近很喜歡跟大家一起玩，越來越融入了呢", "parentFeedback": "謝謝老師諺諺有開心就好", "createdBy": 330019}, {"id": 750001, "weekNumber": 14, "date": "2026-04-04", "studentId": 1, "studentName": "林品逸", "method": "interview", "teacherShare": "品逸最近都會動作比較大要提醒他,再麻煩爸爸跟他溝通溝通", "parentFeedback": "好的在家也是動作大會生氣他", "createdBy": 330019}, {"id": 750002, "weekNumber": 14, "date": "2026-04-04", "studentId": 2, "studentName": "洪明樂", "method": "interview", "teacherShare": "現在早餐麵包都吃很多胃口很呢", "parentFeedback": "好的謝謝老師", "createdBy": 330019}, {"id": 750003, "weekNumber": 14, "date": "2026-04-04", "studentId": 3, "studentName": "張蘊桐", "method": "interview", "teacherShare": "芋頭最近很喜歡模仿大家和老師有些小舉動很好笑呢", "parentFeedback": "在家也是會跟我們聊到呢真可愛", "createdBy": 330019}, {"id": 750004, "weekNumber": 14, "date": "2026-04-04", "studentId": 4, "studentName": "李芊樂", "method": "interview", "teacherShare": "都吃好睡好這禮拜都很開心呢", "parentFeedback": "好得謝謝老師", "createdBy": 330019}, {"id": 750005, "weekNumber": 14, "date": "2026-04-04", "studentId": 5, "studentName": "黃予希", "method": "interview", "teacherShare": "最近希希都喜歡和大家搶玩具,我們都會讓他在旁邊休息一下提醒提醒她在家再麻煩媽媽和希聊聊", "parentFeedback": "好的謝謝老師", "createdBy": 330019}, {"id": 750006, "weekNumber": 12, "date": "2026-03-21", "studentId": 1, "studentName": "林品逸", "method": "interview", "teacherShare": "今天心情都恨好,情緒都很穩定喔", "parentFeedback": "好的謝謝老師", "createdBy": 330019}, {"id": 750007, "weekNumber": 12, "date": "2026-03-21", "studentId": 2, "studentName": "洪明樂", "method": "interview", "teacherShare": "最近跟同學相處得非常好喔~", "parentFeedback": "辛苦老師了", "createdBy": 330019}, {"id": 750008, "weekNumber": 12, "date": "2026-03-21", "studentId": 3, "studentName": "張蘊桐", "method": "interview", "teacherShare": "芋頭很喜歡模仿大家,所以可能有些不好的行為我們會再跟她說說的", "parentFeedback": "謝謝老師的幫忙", "createdBy": 330019}, {"id": 750009, "weekNumber": 12, "date": "2026-03-21", "studentId": 4, "studentName": "李芊樂", "method": "interview", "teacherShare": "這週的情緒起伏很大一點點小挫折就會想哭,我們都會給予安撫和關心", "parentFeedback": "好的謝謝老師", "createdBy": 330019}, {"id": 750010, "weekNumber": 12, "date": "2026-03-21", "studentId": 5, "studentName": "黃予希", "method": "interview", "teacherShare": "早上麵包都吃得不錯,體力也越來越好了中午都很晚才入睡呢", "parentFeedback": "辛苦老師了", "createdBy": 330019}, {"id": 750011, "weekNumber": 12, "date": "2026-03-21", "studentId": 6, "studentName": "吳允希", "method": "interview", "teacherShare": "早上麵包都不太愛吃,會一直玩麵包所以會告訴他不吃了要跟老師說", "parentFeedback": "我們回去會再好好跟她說", "createdBy": 330019}, {"id": 750012, "weekNumber": 12, "date": "2026-03-21", "studentId": 7, "studentName": "楊曜任", "method": "interview", "teacherShare": "阿弟最近都很喜歡跟著同學到處玩模樣很可愛呢", "parentFeedback": "辛苦老師了謝謝", "createdBy": 330019}, {"id": 750013, "weekNumber": 12, "date": "2026-03-21", "studentId": 8, "studentName": "莊又羽", "method": "interview", "teacherShare": "又羽很喜歡跟大家一起玩,但又不喜歡有人拿她東西很矛盾的孩子呢", "parentFeedback": "謝謝老師辛苦了", "createdBy": 330019}, {"id": 750014, "weekNumber": 12, "date": "2026-03-21", "studentId": 9, "studentName": "王鈺棠", "method": "interview", "teacherShare": "最近很喜歡講話,都會聽到他唱歌呢真可愛", "parentFeedback": "在家裡也很喜歡自言自語呢", "createdBy": 330019}, {"id": 750015, "weekNumber": 12, "date": "2026-03-21", "studentId": 10, "studentName": "吳承諺", "method": "interview", "teacherShare": "弟弟最近麵包越吃越好呢", "parentFeedback": "謝謝老師", "createdBy": 330019}, {"id": 750016, "weekNumber": 13, "date": "2026-03-28", "studentId": 1, "studentName": "林品逸", "method": "interview", "teacherShare": "目前在學校已經能告知要去廁所尿尿,越來越厲害", "parentFeedback": "在家也會到馬桶去雖然有時候還是會來不及", "createdBy": 330019}, {"id": 750017, "weekNumber": 13, "date": "2026-03-28", "studentId": 2, "studentName": "洪明樂", "method": "interview", "teacherShare": "午覺都睡得不錯喔,不過還是有控制他睡覺時間", "parentFeedback": "謝謝老師,再麻煩不要超過一個小時半", "createdBy": 330019}, {"id": 750018, "weekNumber": 13, "date": "2026-03-28", "studentId": 3, "studentName": "張蘊桐", "method": "interview", "teacherShare": "最近屁屁的地方有稍微好一些我們也會適當的擦屁屁膏", "parentFeedback": "謝謝老師,目前就是先喝緩瀉劑看能不能改善,大便的狀況再麻煩老師記錄告知我們", "createdBy": 330019}, {"id": 750019, "weekNumber": 13, "date": "2026-03-28", "studentId": 4, "studentName": "李芊樂", "method": "interview", "teacherShare": "這週的狀況都吃好睡好很棒喔", "parentFeedback": "謝謝老師", "createdBy": 330019}, {"id": 750020, "weekNumber": 13, "date": "2026-03-28", "studentId": 5, "studentName": "黃予希", "method": "interview", "teacherShare": "希希很期待要出去玩呢", "parentFeedback": "下週我們要帶他出去玩,真的是幸福得小孩呢", "createdBy": 330019}, {"id": 750021, "weekNumber": 13, "date": "2026-03-28", "studentId": 6, "studentName": "吳允希", "method": "interview", "teacherShare": "希希在班上很受歡迎班上男生都很喜歡圍繞他呢", "parentFeedback": "這麼可愛喔辛苦老師了", "createdBy": 330019}, {"id": 750022, "weekNumber": 13, "date": "2026-03-28", "studentId": 7, "studentName": "楊曜任", "method": "interview", "teacherShare": "很喜歡跟大家搶玩具的阿弟別人拿什麼他也要所以很常在旁邊休息冷靜一下", "parentFeedback": "在家裡也是愛跟姐姐搶,辛苦老師了", "createdBy": 330019}, {"id": 750023, "weekNumber": 13, "date": "2026-03-28", "studentId": 8, "studentName": "莊又羽", "method": "interview", "teacherShare": "又羽只有睡一個小時,出去玩要好好玩唷", "parentFeedback": "好的謝謝老師", "createdBy": 330019}, {"id": 750024, "weekNumber": 13, "date": "2026-03-28", "studentId": 9, "studentName": "王鈺棠", "method": "interview", "teacherShare": "棠棠很喜歡車車,去玩玩具都先拿車而且會自己玩很久呢", "parentFeedback": "在家裡也是很愛車呢", "createdBy": 330019}, {"id": 750025, "weekNumber": 13, "date": "2026-03-28", "studentId": 10, "studentName": "吳承諺", "method": "interview", "teacherShare": "上週都去戶外玩,諺只愛戶外了~雖然看到玩具還是會想要玩真可愛", "parentFeedback": "對阿,公園是他的最愛", "createdBy": 330019}, {"id": 750026, "weekNumber": 14, "date": "2026-04-04", "studentId": 6, "studentName": "吳允希", "method": "interview", "teacherShare": "最近麵包都不太愛吃,吃沒幾個就開始玩起來了", "parentFeedback": "好的會再跟她說辛苦老師了", "createdBy": 330019}, {"id": 750027, "weekNumber": 14, "date": "2026-04-04", "studentId": 7, "studentName": "楊曜任", "method": "interview", "teacherShare": "連假四天~我們下周二見囉辛苦爸媽了", "parentFeedback": "謝謝,辛苦老師了", "createdBy": 330019}, {"id": 750028, "weekNumber": 14, "date": "2026-04-04", "studentId": 8, "studentName": "莊又羽", "method": "interview", "teacherShare": "連假四天,我們下周二見辛苦爸爸媽媽了這一兩天都愛上戴墨鏡的樣子很可愛", "parentFeedback": "對阿 出去玩也都戴著", "createdBy": 330019}, {"id": 780001, "weekNumber": 14, "date": "2026-04-04", "studentId": 9, "studentName": "王鈺棠", "method": "interview", "teacherShare": "堂堂今天玩得很開心~吃得好睡得好喔", "parentFeedback": "謝謝老師", "createdBy": 330019}, {"id": 780002, "weekNumber": 14, "date": "2026-04-04", "studentId": 10, "studentName": "吳承諺", "method": "interview", "teacherShare": "諺很喜歡學校舉辦的兒童節活動都玩得很開心呢", "parentFeedback": "謝謝老師的用心辛苦了", "createdBy": 330019}, {"id": 810001, "weekNumber": 14, "date": "2026-04-02", "studentId": 11, "studentName": "葉紫婕", "method": "interview", "teacherShare": "最近很愛唱大象的歌謠，還會加上動作呢", "parentFeedback": "在家裡也很喜歡跳舞，期待聽到唱大象", "createdBy": 1590028}, {"id": 810002, "weekNumber": 14, "date": "2026-04-02", "studentId": 12, "studentName": "陳奕睿", "method": "interview", "teacherShare": "最近情緒較容易突然大哭，但可以引導他說出想說的話", "parentFeedback": "在家也會突然大哭，會試著引導看看", "createdBy": 1590028}, {"id": 810003, "weekNumber": 14, "date": "2026-04-02", "studentId": 13, "studentName": "許睿桓", "method": "interview", "teacherShare": "早上睡眠時間依然偏長，可以再多觀察", "parentFeedback": "可能跟最近半夜12點會醒來到2-3點入睡有關聯", "createdBy": 1590028}, {"id": 810004, "weekNumber": 14, "date": "2026-04-02", "studentId": 14, "studentName": "蘇彥澄", "method": "interview", "teacherShare": "最近常常突然大哭，適時引導可以緩和下來", "parentFeedback": "在家中也試著依照老師給的建議，持續努力", "createdBy": 1590028}, {"id": 810005, "weekNumber": 14, "date": "2026-04-02", "studentId": 15, "studentName": "李澪", "method": "interview", "teacherShare": "最近情緒有比較快穩定下來，也較願意自主性找同學玩", "parentFeedback": "在家中也會溝通和引導", "createdBy": 1590028}, {"id": 810006, "weekNumber": 14, "date": "2026-04-02", "studentId": 16, "studentName": "余承澔", "method": "interview", "teacherShare": "因感冒關係，有特別留意食慾和精神", "parentFeedback": "在家中也會持續留意狀況", "createdBy": 1590028}, {"id": 810007, "weekNumber": 14, "date": "2026-04-02", "studentId": 17, "studentName": "陳禹澔", "method": "interview", "teacherShare": "目前情緒較容易大哭，會給予引導和安撫", "parentFeedback": "在家中也有大哭情形，也是有多引導", "createdBy": 1590028}, {"id": 810008, "weekNumber": 14, "date": "2026-04-02", "studentId": 18, "studentName": "彭翊宸", "method": "interview", "teacherShare": "情緒上還是會突然大哭，有持續引導及轉移注意力", "parentFeedback": "在家中也會出現大哭，也是嘗試轉移注意力", "createdBy": 1590028}, {"id": 810009, "weekNumber": 14, "date": "2026-04-02", "studentId": 19, "studentName": "林冠邦", "method": "interview", "teacherShare": "近日越來越會獨步走了，目前已可以走10步", "parentFeedback": "在家中也都有勤奮練習，加油", "createdBy": 1590028}, {"id": 810010, "weekNumber": 14, "date": "2026-04-02", "studentId": 20, "studentName": "蔡禾悅", "method": "interview", "teacherShare": "情緒上還是偶爾會不太穩定，給予安撫可緩解，有增加轉移注意力的教具", "parentFeedback": "在家中有試著溝通和轉移注意力，繼續加油", "createdBy": 1590028}, {"id": 840001, "weekNumber": 14, "date": "2026-04-02", "studentId": 21, "studentName": "劉瑀彤", "method": "interview", "teacherShare": "哇！今年是瑀彤第一次在知愛家的兒童節唷~\n老師們非常用心的佈置場地與關卡，讓小朋友們盡情的玩樂，瑀彤玩得不亦樂乎，超級開心呢", "parentFeedback": "謝謝老師，辛苦了", "createdBy": 1440078}, {"id": 840002, "weekNumber": 14, "date": "2026-04-02", "studentId": 22, "studentName": "張瑾馨", "method": "interview", "teacherShare": "哇！今年是瑾馨第一次在知愛家的兒童節唷~\n老師們非常用心的佈置場地與關卡，讓小朋友們盡情的玩樂，瑾馨玩得不亦樂乎，超級開心呢", "parentFeedback": "老師辛苦了", "createdBy": 1440078}, {"id": 840003, "weekNumber": 14, "date": "2026-04-02", "studentId": 23, "studentName": "余硯宸", "method": "interview", "teacherShare": "哇！今年是硯宸第一次在知愛家的兒童節唷~\n老師們非常用心的佈置場地與關卡，讓小朋友們盡情的玩樂，硯宸玩得不亦樂乎，超級開心呢", "parentFeedback": "謝謝老師", "createdBy": 1440078}, {"id": 840004, "weekNumber": 14, "date": "2026-04-02", "studentId": 24, "studentName": "蔡雨彤", "method": "interview", "teacherShare": "哇！今年是雨彤第一次在知愛家的兒童節唷~\n老師們非常用心的佈置場地與關卡，讓小朋友們盡情的玩樂，雨彤玩得不亦樂乎，超級開心呢", "parentFeedback": "Ok", "createdBy": 1440078}, {"id": 840005, "weekNumber": 14, "date": "2026-04-02", "studentId": 25, "studentName": "黃映澄", "method": "interview", "teacherShare": "哇！今年是澄澄第一次在知愛家的兒童節唷~\n老師們非常用心的佈置場地與關卡，讓小朋友們盡情的玩樂，澄澄玩得不亦樂乎，超級開心呢", "parentFeedback": "老師辛苦了", "createdBy": 1440078}, {"id": 840006, "weekNumber": 14, "date": "2026-04-02", "studentId": 35, "studentName": "賴時儀", "method": "interview", "teacherShare": "哇！今年是時儀第一次在知愛家的兒童節唷~\n老師們非常用心的佈置場地與關卡，讓小朋友們盡情的玩樂，時儀玩得不亦樂乎，超級開心呢", "parentFeedback": "謝謝老師", "createdBy": 1440078}, {"id": 840007, "weekNumber": 14, "date": "2026-04-02", "studentId": 90001, "studentName": "陳語湉", "method": "interview", "teacherShare": "語湉這兩天入托狀況良好唷，看到老師會笑著揮手打招呼，模樣相當可愛！在活動過程中還在主動分享玩具給同學，超棒的", "parentFeedback": "媽媽原本很擔心語湉會不能適應，看到老師聯絡簿寫得狀況，跟語湉的生活照片之後，媽媽放心很多，謝謝老師！", "createdBy": 1440078}, {"id": 840008, "weekNumber": 14, "date": "2026-04-02", "studentId": 26, "studentName": "林逸宸", "method": "interview", "teacherShare": "哇！今年是逸宸第一次在知愛家的兒童節唷~\n老師們非常用心的佈置場地與關卡，讓小朋友們盡情的玩樂，逸宸玩得不亦樂乎，超級開心呢", "parentFeedback": "謝謝老師，辛苦了", "createdBy": 1440078}, {"id": 840009, "weekNumber": 14, "date": "2026-04-02", "studentId": 28, "studentName": "陳品叡", "method": "interview", "teacherShare": "哇！今年是可樂第一次在知愛家的兒童節唷~\n老師們非常用心的佈置場地與關卡，讓小朋友們盡情的玩樂，可樂玩得不亦樂乎，超級開心呢", "parentFeedback": "辛苦老師了", "createdBy": 1440078}, {"id": 840010, "weekNumber": 14, "date": "2026-04-02", "studentId": 29, "studentName": "林禹順", "method": "interview", "teacherShare": "哇！今年是順順第一次在知愛家的兒童節唷~\n老師們非常用心的佈置場地與關卡，讓小朋友們盡情的玩樂，順順玩得不亦樂乎，超級開心呢", "parentFeedback": "謝謝老師", "createdBy": 1440078}, {"id": 840011, "weekNumber": 14, "date": "2026-04-02", "studentId": 27, "studentName": "謝知愛", "method": "interview", "teacherShare": "哇！今年是知愛第一次在知愛家的兒童節唷~\n老師們非常用心的佈置場地與關卡，讓小朋友們盡情的玩樂，知愛玩得不亦樂乎，超級開心呢", "parentFeedback": "老師們辛苦了", "createdBy": 1440078}, {"id": 870001, "weekNumber": 14, "date": "2026-04-01", "studentId": 30, "studentName": "陳杏恩", "method": "interview", "teacherShare": "今日讓寶貝進行兒童節打地鼠活動，他喜歡也蠻會敲打的。", "parentFeedback": "家裡也有一支槌子，他常常拿著到處敲，這個他應該蠻擅長的；杏恩4/2打預防針，晚點到校。", "createdBy": 750001}, {"id": 870002, "weekNumber": 14, "date": "2026-03-31", "studentId": 32, "studentName": "吳允霏", "method": "interview", "teacherShare": "今日讓寶貝進行兒童節活動：釣魚，他釣起來後，就直接把魚抓起來。", "parentFeedback": "在家也是抓握各種東西，什麼都要把玩一下，非常有好奇心！允霏4/7（二）請事假，要出去玩。", "createdBy": 750001}, {"id": 870003, "weekNumber": 14, "date": "2026-04-02", "studentId": 33, "studentName": "黃語則", "method": "phone", "teacherShare": "早上語則吃完粥後，坐在安撫椅上，太興奮手開心揮動手時，手指甲抓到左額頭上方，老師會持續留意避免他再抓；最近他口水，比較多老師有幫他勤換口水巾。", "parentFeedback": "再麻煩老師留意則則，謝謝！喝奶部分，想改成早上吃副食品完，直接再泡60cc;接著，每個四小時餵一次奶，奶量180cc。", "createdBy": 750001}, {"id": 870004, "weekNumber": 14, "date": "2026-03-31", "studentId": 30001, "studentName": "黃梓芸", "method": "interview", "teacherShare": "今日有排便兩次，屁股有些微紅，可以幫寶貝準備屁屁膏；奶也喝的不錯！都有喝到140-150cc。", "parentFeedback": "好的，謝謝老師。", "createdBy": 750001}, {"id": 870005, "weekNumber": 14, "date": "2026-03-31", "studentId": 34, "studentName": "張語恩", "method": "interview", "teacherShare": "今日讓寶貝體驗兒童節活動釣魚及做兒童節卡片，他情緒很穩定地參與所有的的活動，很棒！做卡片時笑咪咪的，很喜歡呢！", "parentFeedback": "謝謝老師；語恩奶量調整為130cc,每3到3.5小時餵一次。", "createdBy": 750001}, {"id": 870006, "weekNumber": 14, "date": "2026-03-31", "studentId": 60001, "studentName": "高士鵬", "method": "interview", "teacherShare": "今天讓寶貝體驗兒童節活動：釣魚及做兒童節卡片，老師慢慢引導他一起參與；有幫寶貝多拍嗝。", "parentFeedback": "謝謝！他比較容易溢奶，有時喝完過好一陣子都還會，再請老師留意；奶改成泡130cc,三小時餵一次。", "createdBy": 750001}, {"id": 900001, "weekNumber": 15, "date": "2026-04-07", "studentId": 21, "studentName": "劉瑀彤", "method": "interview", "teacherShare": "今天活動時間的時候，老師唱著（小星星）帶著班上小朋友一起唱，結果瑀彤超厲害的，一字不漏的跟上老師的速度與節奏，整首唱完，同學聽完後還會主動拍手說好棒，超歡樂的一天耶🥳🥳", "parentFeedback": "瑀彤還會很多其他的兒歌唷，是外婆教的☺️☺️", "createdBy": 1440078}, {"id": 900002, "weekNumber": 15, "date": "2026-04-07", "studentId": 25, "studentName": "黃映澄", "method": "interview", "teacherShare": "今天幫澄澄擦藥的時候，澄澄很害怕，手手一直想要縮起來，一點小哭哭，但老師安撫加引導後，澄澄很勇敢的讓老師擦完藥，並且包紮好，超棒的♥️♥️♥️", "parentFeedback": "謝謝老師", "createdBy": 1440078}, {"id": 900003, "weekNumber": 15, "date": "2026-04-07", "studentId": 90001, "studentName": "陳語湉", "method": "interview", "teacherShare": "今天是大福入托的第二個禮拜，適應的相當好唷！早上開心的跟同學一起玩，玩到一半還會故意離開老師視線，跟老師玩躲貓貓，被老師發現到她的時候，笑得好燦爛呀！可愛☺️☺️☺️", "parentFeedback": "大福很喜歡笑，謝謝老師的陪伴", "createdBy": 1440078}, {"id": 930001, "weekNumber": 15, "date": "2026-04-10", "studentId": 22, "studentName": "張瑾馨", "method": "interview", "teacherShare": "瑾馨好貼心，看到同學在哭哭，馬上過去拍拍同學的背，而且還會對著同學說秀秀...\n老師稱讚她好棒的時候，瑾馨笑得好開心！🥰🥰🥰", "parentFeedback": "哇~這麼貼心呀！謝謝老師平常對瑾馨的教導", "createdBy": 1440078}, {"id": 930002, "weekNumber": 15, "date": "2026-04-10", "studentId": 23, "studentName": "余硯宸", "method": "interview", "teacherShare": "最近硯宸跟同學在玩玩具的時候，分享慾爆棚，雙手捧上好幾個玩具，到處發給同學，同學還一臉疑惑的看著他，畫面相當可愛又有趣😝", "parentFeedback": "真的呀？好有趣的畫面xd", "createdBy": 1440078}, {"id": 930003, "weekNumber": 15, "date": "2026-04-10", "studentId": 24, "studentName": "蔡雨彤", "method": "interview", "teacherShare": "最近有發現雨彤會跟著同學把自己的被被折了一遍又一遍，結果都最後是整張床都被雨彤創作了一番，老師都覺得既好玩又有趣😂😂", "parentFeedback": "想像力太豐富了吧xd", "createdBy": 1440078}, {"id": 930004, "weekNumber": 15, "date": "2026-04-10", "studentId": 26, "studentName": "林逸宸", "method": "interview", "teacherShare": "逸宸最近爬好快，看到老師準備好玩具後，他第一個衝上去抓了一大把，拿到手的感覺似乎很有成就感，還會轉頭對著老師笑，表示他拿到他喜歡的玩具囉，太可愛了啦😝", "parentFeedback": "哈哈！在家有時也會這樣子，喜歡玩的逸宸😁", "createdBy": 1440078}, {"id": 930005, "weekNumber": 15, "date": "2026-04-10", "studentId": 28, "studentName": "陳品叡", "method": "interview", "teacherShare": "可樂最近很會表達自己，看到老師在餵同學吃飯的時候，會伸手拍拍老師的肩膀，表示他也餓了！老師回應他說馬上就換他吃囉，他還會開心的笑著，真的好棒呀！🥰", "parentFeedback": "哇！這麼棒呀...\n謝謝老師的照顧", "createdBy": 1440078}, {"id": 930006, "weekNumber": 15, "date": "2026-04-10", "studentId": 29, "studentName": "林禹順", "method": "interview", "teacherShare": "順順這幾天的屁屁還是蠻紅的，有把他擦了屁屁膏，但他可能因為不舒服，有點鬧情緒，老師安撫引導後，順順情緒有穩定下來，開心跟老師互動！☺️☺️☺️", "parentFeedback": "謝謝老師，辛苦了", "createdBy": 1440078}, {"id": 960001, "weekNumber": 15, "date": "2026-04-10", "studentId": 30, "studentName": "陳杏恩", "method": "phone", "teacherShare": "杏恩昨日食慾很好，精神活力也都不錯，大約到傍晚五點多才開始發燒，她今日身體狀況還好嗎？她的尿布快沒了，再請爸爸幫他準備。", "parentFeedback": "好的，下午拿寢具時，會帶尿布過去；目前低燒，醫師說可能是因為先打疫苗的關係再觀察，今日在家中精神活力也都很好。", "createdBy": 750001}, {"id": 960002, "weekNumber": 15, "date": "2026-04-07", "studentId": 32, "studentName": "吳允霏", "method": "interview", "teacherShare": "早上入中心後先補眠，食慾都正常，下午副食品吃比較少，有再補泡奶讓他喝，今日有便便，媽媽再觀察他的狀況。", "parentFeedback": "好的，謝謝老師，他去日本都很乖，預期他今天會睡比較多，可能吃藥身體不適；不好意思，本週去日本，備品下週末再一起補上。", "createdBy": 750001}, {"id": 960003, "weekNumber": 15, "date": "2026-04-09", "studentId": 33, "studentName": "黃語則", "method": "interview", "teacherShare": "老師準備的副食品100ml他都有吃光，每次喝奶都會分兩段喝，比較注重睡眠，沒辦法一次喝到180cc；讓寶貝進行袋鼠跳跳跳活動，抱著則則體驗。", "parentFeedback": "他在家也是很重睡眠，回家只喝一次奶，就會一直睡，半夜沒有喝，在中心時請改回三小時喝一次，每次150cc，謝謝老師！袋鼠小隊很可愛呢！", "createdBy": 750001}, {"id": 960004, "weekNumber": 15, "date": "2026-04-10", "studentId": 30001, "studentName": "黃梓芸", "method": "interview", "teacherShare": "請爸爸幫寶貝準備尿布；最近口水比較多，會沾溼上衣及手套，所以小手套及衣物都有更換，但仍有點口水疹狀況；很喜歡翻身；這兩日沒有流鼻涕狀況。", "parentFeedback": "謝謝老師，那不用再吃藥。他在家想睡覺、比較興奮激動時都會用手抓頭，再請老師留意。", "createdBy": 750001}, {"id": 960005, "weekNumber": 15, "date": "2026-04-08", "studentId": 34, "studentName": "張語恩", "method": "interview", "teacherShare": "他趴在大型軟積木上，有點搖晃時，他情緒也都很穩定，很勇敢！喝奶今日每餐都喝120cc，泡140cc是說加奶粉前水量140cc嗎？還是加完奶粉後的總量？", "parentFeedback": "謝謝讓他各種體驗；泡140cc是說加奶粉前，水量120cc，加奶後才快140cc。", "createdBy": 750001}, {"id": 990001, "weekNumber": 15, "date": "2026-04-10", "studentId": 11, "studentName": "葉紫婕", "method": "interview", "teacherShare": "目前可以自己吃飯，但偶爾盛飯還是不大會", "parentFeedback": "目前在家中也都會練習", "createdBy": 1590028}, {"id": 990002, "weekNumber": 15, "date": "2026-04-10", "studentId": 12, "studentName": "陳奕睿", "method": "interview", "teacherShare": "目前在中心可以依照指示完成指令，中文加英文的單詞也練習得很好", "parentFeedback": "目前在家裡指令上的完成度挺高的，單詞的部分在家裡也都會自己練習自己講", "createdBy": 1590028}, {"id": 990003, "weekNumber": 15, "date": "2026-04-10", "studentId": 13, "studentName": "許睿桓", "method": "interview", "teacherShare": "目前在學校都會主動和同學溝通，大多以發音的方式來表達自己的需求", "parentFeedback": "目前在家裡也都會多加引導，最近也有發現發音的次數相較於以往更多", "createdBy": 1590028}, {"id": 990004, "weekNumber": 15, "date": "2026-04-10", "studentId": 14, "studentName": "蘇彥澄", "method": "interview", "teacherShare": "目前在中心有學習中文加英文的單詞練習，學習的成果不錯", "parentFeedback": "在家裡和在戶外活動的時候，也都會自主說出不同的單詞，在表達自己的需求時也都進步很多", "createdBy": 1590028}, {"id": 990005, "weekNumber": 15, "date": "2026-04-10", "studentId": 15, "studentName": "李澪", "method": "interview", "teacherShare": "老師們觀察到這週有明顯的進步很多，例如會主動找兩位老師抱抱，吃飯的情形也有進步，很愛吃水果", "parentFeedback": "在家裡也很愛吃水果，聽到老師說在學校和老師互動良好，感到很欣慰", "createdBy": 1590028}, {"id": 990006, "weekNumber": 15, "date": "2026-04-10", "studentId": 16, "studentName": "余承澔", "method": "interview", "teacherShare": "目前在中心偶爾還是會出現搶同學玩具或推擠同學的行為，但是在引導後持續努力進步中", "parentFeedback": "謝謝老師在學校的多方引導，希望會越來越進步", "createdBy": 1590028}, {"id": 990007, "weekNumber": 15, "date": "2026-04-10", "studentId": 17, "studentName": "陳禹澔", "method": "interview", "teacherShare": "目前在中心情緒管理上有進步很多，老師也會用鼓勵的方式來引導", "parentFeedback": "在家裡偶爾還是會出現情緒起伏較大的情形，家長也都有依照老師的建議去做相關性的引導", "createdBy": 1590028}, {"id": 990008, "weekNumber": 15, "date": "2026-04-10", "studentId": 18, "studentName": "彭翊宸", "method": "interview", "teacherShare": "目前在中心還是會有抓同學頭髮的情況發生，目前老師也依然是用引導的方式來教導對同學動作輕柔", "parentFeedback": "目前在家中和去戶外活動時，偶爾還是會出現想要抓頭髮推別人的行為，家長也都還在努力引導中", "createdBy": 1590028}, {"id": 990009, "weekNumber": 15, "date": "2026-04-10", "studentId": 19, "studentName": "林冠邦", "method": "interview", "teacherShare": "這一週下來走路的步數有越來越多，也不需要老師特別催促走路，自己也很願意獨步走", "parentFeedback": "在家中也都會自己走很多路，父母親的陪伴之下，有越來越進步中，謝謝老師們的幫忙和陪伴引導", "createdBy": 1590028}, {"id": 990010, "weekNumber": 15, "date": "2026-04-10", "studentId": 20, "studentName": "蔡禾悅", "method": "interview", "teacherShare": "目前在中心偶爾還是會出現情緒起伏較大的情形，但大多老師安撫之下可恢復平穩", "parentFeedback": "目前在家裡情緒上偶爾還是波動比較大，但在戶外活動時有父母的陪同之下心情好很多", "createdBy": 1590028}, {"id": 1020001, "weekNumber": 16, "date": "2026-04-15", "studentId": 21, "studentName": "劉瑀彤", "method": "interview", "teacherShare": "今天健康檢查時，醫生看到瑀彤紅腫的眼睛為結膜炎，需看醫生，盡量不要讓瑀彤有揉眼睛的動作...", "parentFeedback": "好的，沒問題！放學後會帶瑀彤去看醫生，謝謝老師", "createdBy": 1440078}, {"id": 1020002, "weekNumber": 16, "date": "2026-04-15", "studentId": 23, "studentName": "余硯宸", "method": "interview", "teacherShare": "今天健康檢查時，醫生有幫硯宸看看腳型，雙腳比較處於內八狀況，走路會常相互重疊而跌倒，家長可帶硯宸至復健科看診或找物理治療師協助觀察...", "parentFeedback": "好的！近期會帶硯宸往這方面尋求幫助，謝謝老師", "createdBy": 1440078}, {"id": 1050001, "weekNumber": 16, "date": "2026-04-16", "studentId": 22, "studentName": "張瑾馨", "method": "interview", "teacherShare": "最近有發現瑾馨生氣的時候會打自己的頭，老師看到立即制止並安撫情緒後，引導瑾馨這是不對的行為，事後瑾馨這樣的情況有改善了很多！老師會再多多注意瑾馨的在校情況，予以告知家長", "parentFeedback": "瑾馨在家生氣也會有如此的行為，媽媽也有引導瑾馨不要這樣做！謝謝老師，辛苦了", "createdBy": 1440078}, {"id": 1080001, "weekNumber": 16, "date": "2026-04-13", "studentId": 90001, "studentName": "陳語湉", "method": "interview", "teacherShare": "語湉最近會偷偷觀察同學在做什麼，看著看著還不上揚嘴巴跟著同學笑呵呵，發現老師看到她那模樣時，還會害羞躲進來，好可愛😁😁", "parentFeedback": "語湉就是個很喜歡笑的寶貝，謝謝老師這麼照顧語湉♥️♥️", "createdBy": 1440078}, {"id": 1110001, "weekNumber": 16, "date": "2026-04-15", "studentId": 33, "studentName": "黃語則", "method": "interview", "teacherShare": "明天塗氟八點半前到校，帶健保卡、寶寶手冊；媽咪詢問增加奶量一事，則則喝較慢，易睡著，老師餵得辛苦，寶貝更辛苦！考量寶貝情緒，建議四小時喝一次，奶量150cc。", "parentFeedback": "好的，讓孩子開心喝，先照老師說的方式進行。明日十點爸爸會帶則則去超音波檢查，檢查完會再返回中心。", "createdBy": 750001}, {"id": 1110002, "weekNumber": 16, "date": "2026-04-15", "studentId": 30, "studentName": "陳杏恩", "method": "interview", "teacherShare": "今日身體檢查，杏恩情緒穩定很棒！順利完成檢查，檢查前有先讓寶貝拿聽診器角色扮演，他很喜歡！明日請八點半前到校塗氟。", "parentFeedback": "每次看醫生，杏恩都想偷拿醫師的聽診器，這次得手了，哈哈！", "createdBy": 750001}, {"id": 1110003, "weekNumber": 16, "date": "2026-04-14", "studentId": 32, "studentName": "吳允霏", "method": "interview", "teacherShare": "最近允霏喜歡出聲音和同學互動，也會模仿同學動作；明天請八點半前到校健康檢查，並帶健保卡和寶寶手冊。", "parentFeedback": "希望霏霏明天能乖乖讓醫師檢查。", "createdBy": 750001}, {"id": 1110004, "weekNumber": 16, "date": "2026-04-17", "studentId": 30001, "studentName": "黃梓芸", "method": "interview", "teacherShare": "這兩日喝奶速度有進步；梓芸想喝奶或睡覺前，會雙手揮自己的頭部，老師會幫他戴上手套。", "parentFeedback": "他在家也是如此，會抓自己的頭，有時會破皮。", "createdBy": 750001}, {"id": 1110005, "weekNumber": 16, "date": "2026-04-16", "studentId": 34, "studentName": "張語恩", "method": "interview", "teacherShare": "今日語恩滿四個月，中心為寶貝舉行收涎活動，孩子今天活動時心情都很好唷。", "parentFeedback": "沒想到有被留意到滿四個月的日期，還特地幫他收涎，真的又驚又喜！謝謝老師！", "createdBy": 750001}, {"id": 1140001, "weekNumber": 16, "date": "2026-04-17", "studentId": 24, "studentName": "蔡雨彤", "method": "interview", "teacherShare": "最近很喜歡跟同學玩在一起，玩著玩著還會一起哈哈大笑，笑得有點浮誇的那種，老師跟其他同學看了也跟著一起笑，太可愛了😂", "parentFeedback": "越來越調皮xd", "createdBy": 1440078}, {"id": 1140002, "weekNumber": 16, "date": "2026-04-17", "studentId": 25, "studentName": "黃映澄", "method": "interview", "teacherShare": "有發現澄澄不太喜歡被同學碰觸到自己，如果被碰觸到的當下，澄澄會發出生氣的聲音，老師引導後澄澄有比較穩定，會拿著玩具跑來跟老師一起玩，哈哈！很有趣", "parentFeedback": "那她應該沒有欺負同學吧？！xd\n再麻煩老師多留意她的行為，謝謝老師", "createdBy": 1440078}, {"id": 1140003, "weekNumber": 16, "date": "2026-04-17", "studentId": 35, "studentName": "賴時儀", "method": "interview", "teacherShare": "最近時儀心情不錯喔，活動期間自己玩到一半會突然轉身跑來跟老師互動，老師回應她的同時，還會笑得露出那幾顆可愛的小牙齒，好歡樂呀🥳", "parentFeedback": "哇，這麼有趣的畫面呀！？謝謝老師的照顧♥️", "createdBy": 1440078}, {"id": 1170001, "weekNumber": 16, "date": "2026-04-15", "studentId": 26, "studentName": "林逸宸", "method": "interview", "teacherShare": "好的，沒問題！有時候老師在幫逸宸穿襪子之後，他為了快速拿到玩具，會自己把襪子扯掉，三步併兩步的爬去拿玩具，很有趣", "parentFeedback": "再麻煩老師幫逸宸穿小背心跟襪子，辛苦了", "createdBy": 1440078}, {"id": 1170002, "weekNumber": 16, "date": "2026-04-16", "studentId": 27, "studentName": "謝知愛", "method": "interview", "teacherShare": "知愛滿一歲後，真的是越來越可愛餒，跟她互動的過程中笑得比誰都還開心，尤其是那對嘴邊肉，好Q彈！🥰🥰", "parentFeedback": "是不是！有沒有常常偷捏😂", "createdBy": 1440078}, {"id": 1170003, "weekNumber": 16, "date": "2026-04-16", "studentId": 28, "studentName": "陳品叡", "method": "interview", "teacherShare": "可樂最近會慢慢放手撐個一秒至兩秒後，坐下來用爬的到老師身邊撒嬌，看來可樂已經要學會走路囉，真棒🥰🥰", "parentFeedback": "哇，可樂長大了！不知道會不會越來越調皮xd", "createdBy": 1440078}, {"id": 1170004, "weekNumber": 16, "date": "2026-04-17", "studentId": 29, "studentName": "林禹順", "method": "interview", "teacherShare": "順順最近午睡醒來後會跟自己玩欸，尤其是他最愛的奶嘴，自己把玩一會兒之後還會自己笑自己，被老師發現時還會害羞躺下躲進被子裡，實在太可愛啦🥳", "parentFeedback": "順順就是這個搞笑😂", "createdBy": 1440078}, {"id": 1200001, "weekNumber": 16, "date": "2026-04-14", "studentId": 60001, "studentName": "高士鵬", "method": "interview", "teacherShare": "寶貝奶粉快沒了，請幫鵬鵬準備奶粉；鵬鵬都會看著老師，好像在想什麼。", "parentFeedback": "好；他可能在想喝奶，想說我的奶在哪裏？謝謝老師讓寶貝睡得安穩。", "createdBy": 750001}, {"id": 1230001, "weekNumber": 16, "date": "2026-04-17", "studentId": 11, "studentName": "葉紫婕", "method": "interview", "teacherShare": "最近練習用餐具吃飯的情形有越來越進步，近日發現皆是用左手吃飯，和媽媽做溝通也可接受持續練習左手即可", "parentFeedback": "最近在家中也發現皆使用左手吃比較順利，目前就配合中心也都用左手吃飯", "createdBy": 1590028}, {"id": 1230002, "weekNumber": 16, "date": "2026-04-17", "studentId": 12, "studentName": "陳奕睿", "method": "interview", "teacherShare": "在學校有和媽媽說立體動物模型比較認不出動物的名稱，持續努力加油", "parentFeedback": "謝謝老師的建議，在家裡會增加立體模型動物方面的知識學習", "createdBy": 1590028}, {"id": 1230003, "weekNumber": 16, "date": "2026-04-17", "studentId": 13, "studentName": "許睿桓", "method": "interview", "teacherShare": "最近也都有持續引導開口說話，希望會越來越進步", "parentFeedback": "在家裡也都有持續努力練習，也鼓勵多開口講話", "createdBy": 1590028}, {"id": 1230004, "weekNumber": 16, "date": "2026-04-17", "studentId": 14, "studentName": "蘇彥澄", "method": "interview", "teacherShare": "最近因為體重的關係，有和父母溝通，若是單純的飯菜不吃，也都會持續增加水果進去，吃得還不錯", "parentFeedback": "目前也因為體重的關係在家裡也都會將水果先加入飯菜中一起食用，希望體重可以先增加一些", "createdBy": 1590028}, {"id": 1230005, "weekNumber": 16, "date": "2026-04-17", "studentId": 15, "studentName": "李澪", "method": "interview", "teacherShare": "目前在學校的情緒方面都相對穩定，對語言上的學習也都蠻專注的", "parentFeedback": "在家裡也都會進行語言方面的學習，對於音樂和教具方面的使用上熱衷度也蠻高的", "createdBy": 1590028}, {"id": 1230006, "weekNumber": 16, "date": "2026-04-17", "studentId": 16, "studentName": "余承澔", "method": "interview", "teacherShare": "目前練習自主用餐時盛飯有比以前更進步一些，透過老師從旁引導希望會越來越進步", "parentFeedback": "目前在外吃飯時也都會鼓勵自主用餐，希望會越來越進步", "createdBy": 1590028}, {"id": 1230007, "weekNumber": 16, "date": "2026-04-17", "studentId": 17, "studentName": "陳禹澔", "method": "interview", "teacherShare": "在學校觀察到，眼睛周圍有比較泛紅，已經告知媽媽此情況，持續用眼藥水追蹤情形", "parentFeedback": "目前在家裡也都有持續點眼藥水觀察情況，也請老師協助減少用手揉眼睛的次數", "createdBy": 1590028}, {"id": 1230008, "weekNumber": 16, "date": "2026-04-17", "studentId": 18, "studentName": "彭翊宸", "method": "interview", "teacherShare": "最近都有讓小朋友自己練習用牙刷自主刷牙，上排牙齒刷得沒那麼好，持續練習中", "parentFeedback": "在家裡有聽老師的建議鼓勵小朋友自主刷牙，謝謝老師的提醒和建議", "createdBy": 1590028}, {"id": 1230009, "weekNumber": 16, "date": "2026-04-17", "studentId": 19, "studentName": "林冠邦", "method": "interview", "teacherShare": "最近都有些許感冒症狀，持續留意咳嗽是否有痰音，及鼻水的濃稠度和顏色以及量的性質", "parentFeedback": "在家裡有使用蒸氣物化，希望小朋友的感冒可以加快改善", "createdBy": 1590028}, {"id": 1230010, "weekNumber": 16, "date": "2026-04-17", "studentId": 20, "studentName": "蔡禾悅", "method": "interview", "teacherShare": "最近發現喝水的情形有越來越進步，老師也會增加給喝水的次數及鼓勵", "parentFeedback": "謝謝老師們的引導和協助，最近在家裡小朋友喝水的情形越來越進步", "createdBy": 1590028}, {"id": 1260001, "weekNumber": 16, "date": "2026-04-15", "studentId": 1, "studentName": "林品逸", "method": "interview", "teacherShare": "品逸真的是越來越有個性，好在老師跟他慢慢溝通後他就會冷靜，再麻煩爸爸回家也多跟他溝通溝通了！", "parentFeedback": "沒問題，在家也是都要跟他溝通好久呢！", "createdBy": 390021}, {"id": 1260002, "weekNumber": 16, "date": "2026-04-15", "studentId": 2, "studentName": "洪明樂", "method": "interview", "teacherShare": "明樂越來越會表達自己的想法了！每天來學校都迫不期待的要跟同學們聊天！", "parentFeedback": "在家裡也是，都跟爸爸媽媽聊不停了！", "createdBy": 390021}, {"id": 1260003, "weekNumber": 15, "date": "2026-04-10", "studentId": 1, "studentName": "林品逸", "method": "interview", "teacherShare": "這週的品逸表現都很好喔～雖然有些調皮但是偶爾會展現出大哥哥的風範唷。", "parentFeedback": "哈哈真棒", "createdBy": 330019}, {"id": 1260004, "weekNumber": 16, "date": "2026-04-15", "studentId": 3, "studentName": "張蘊桐", "method": "interview", "teacherShare": "最近開始都有在訓練芋頭要坐小馬桶大便，但目前還要再繼續努力，因為芋頭都會上下去才跟老師說，大家一起努力！", "parentFeedback": "感謝老師，芋頭在家也是，大家一起努力加油！", "createdBy": 390021}, {"id": 1260005, "weekNumber": 15, "date": "2026-04-10", "studentId": 2, "studentName": "洪明樂", "method": "interview", "teacherShare": "明樂知道要放假了，在學校玩得很開心～也和同學一起分享玩具唷。", "parentFeedback": "很棒呢，謝謝老師", "createdBy": 330019}, {"id": 1260006, "weekNumber": 16, "date": "2026-04-15", "studentId": 4, "studentName": "李芊樂", "method": "interview", "teacherShare": "芊樂的表達能力越來越好了呢！每天來學校都會一直跟老師分享他都做了些什麼～～", "parentFeedback": "非常棒，繼續保持，哈！", "createdBy": 390021}, {"id": 1260007, "weekNumber": 15, "date": "2026-04-10", "studentId": 3, "studentName": "張蘊桐", "method": "interview", "teacherShare": "芋頭這週也是玩好玩滿，連假回來還能開開心的玩超棒的", "parentFeedback": "週末也有帶芋頭去新竹放放電，不怕生的到處交談呢", "createdBy": 330019}, {"id": 1260008, "weekNumber": 16, "date": "2026-04-15", "studentId": 5, "studentName": "黃予希", "method": "interview", "teacherShare": "予希是班上的小幫手呢！看到同學需要幫忙時都會去幫忙喔！", "parentFeedback": "在家裡也是，都會幫忙爸爸媽媽～", "createdBy": 390021}, {"id": 1260009, "weekNumber": 15, "date": "2026-04-10", "studentId": 4, "studentName": "李芊樂", "method": "interview", "teacherShare": "連假回來的小小有些情緒但很快的就被玩具吸引了～實在太可愛了", "parentFeedback": "哈哈有吃的玩的就好了，謝謝老師", "createdBy": 330019}, {"id": 1260010, "weekNumber": 16, "date": "2026-04-15", "studentId": 6, "studentName": "吳允希", "method": "interview", "teacherShare": "允希真的是每天都活力滿滿呢！到學校就開始一直講話講不停，真的是好可愛❤️", "parentFeedback": "感謝老師的照顧，允希在學校真的玩的好開心呀！", "createdBy": 390021}, {"id": 1260011, "weekNumber": 15, "date": "2026-04-10", "studentId": 5, "studentName": "黃予希", "method": "interview", "teacherShare": "連假回來的一週，希希也玩的很開心，和同學一起分享玩具～非常棒喔", "parentFeedback": "謝謝老師", "createdBy": 330019}, {"id": 1260012, "weekNumber": 16, "date": "2026-04-15", "studentId": 7, "studentName": "楊曜任", "method": "interview", "teacherShare": "曜任有成功的在小馬桶上大便囉！老師們會繼續努力幫曜任把尿布戒掉的！", "parentFeedback": "謝謝老師，辛苦了！", "createdBy": 390021}, {"id": 1260013, "weekNumber": 15, "date": "2026-04-10", "studentId": 6, "studentName": "吳允希", "method": "interview", "teacherShare": "希希越來越有小女人的風範，打扮的模樣真可愛", "parentFeedback": "希希也喜歡看媽媽化妝呢，還會說好好看😻", "createdBy": 330019}, {"id": 1260014, "weekNumber": 16, "date": "2026-04-15", "studentId": 8, "studentName": "莊又羽", "method": "interview", "teacherShare": "又羽非常愛他的墨鏡呢！帶來學校後就一直拿在手上，同學一靠近還會擋著不讓拿呢，真是有趣！", "parentFeedback": "又羽真的是一個非常有個性的孩子呢！", "createdBy": 390021}, {"id": 1260015, "weekNumber": 16, "date": "2026-04-15", "studentId": 9, "studentName": "王鈺棠", "method": "interview", "teacherShare": "棠棠越來越愛說話了呢！每天到學校都講不停，真是可愛！", "parentFeedback": "在家裡也很喜歡和家人聊天，謝謝老師！", "createdBy": 390021}, {"id": 1260016, "weekNumber": 15, "date": "2026-04-10", "studentId": 7, "studentName": "楊曜任", "method": "interview", "teacherShare": "阿弟這週也是玩好玩滿，越來越有自己的想法，都快抓不住了呢", "parentFeedback": "在家也是呢", "createdBy": 330019}, {"id": 1260017, "weekNumber": 16, "date": "2026-04-15", "studentId": 10, "studentName": "吳承諺", "method": "interview", "teacherShare": "諺諺還是有在稍微的流鼻涕喔！不過咳嗽的部分有好多了喔！", "parentFeedback": "謝謝老師，回家後會再繼續觀察！", "createdBy": 390021}, {"id": 1260018, "weekNumber": 15, "date": "2026-04-10", "studentId": 8, "studentName": "莊又羽", "method": "interview", "teacherShare": "又羽很喜歡觀察寶寶，還會和寶寶一起玩照顧寶寶，很有大姐姐的模樣喔真棒", "parentFeedback": "在家也會照顧娃娃呢", "createdBy": 330019}, {"id": 1260019, "weekNumber": 15, "date": "2026-04-10", "studentId": 9, "studentName": "王鈺棠", "method": "interview", "teacherShare": "棠棠最近學會了很多的小技能喔，模樣超可愛的", "parentFeedback": "棠棠回家也會學給媽媽看呢，謝謝老師", "createdBy": 330019}, {"id": 1260020, "weekNumber": 15, "date": "2026-04-10", "studentId": 10, "studentName": "吳承諺", "method": "interview", "teacherShare": "諺諺看到媽媽回來了，早上都比較黏著媽媽，但進來中心後就被玩具吸引了呢～", "parentFeedback": "哈哈有愛的玩具玩真棒", "createdBy": 330019}, {"id": 1260021, "weekNumber": 15, "date": "2026-04-10", "studentId": 27, "studentName": "謝知愛", "method": "interview", "teacherShare": "可愛的孩子，每天都笑嘻嘻看到他都好療癒，最近都在訓練他獨立站，不過她還是最愛黏在老師身上呢", "parentFeedback": "謝謝老師辛苦囉", "createdBy": 330019}, {"id": 1290001, "weekNumber": 17, "date": "2026-04-21", "studentId": 1, "studentName": "林品逸", "method": "interview", "teacherShare": "今天的課程品逸最喜歡的是卷壽司，看到床墊就躺好立馬想被捲起來呢，看的老師都也想一起躺好裹起來😂", "parentFeedback": "品逸太大隻了要捲不住了", "createdBy": 330019}, {"id": 1290002, "weekNumber": 17, "date": "2026-04-21", "studentId": 2, "studentName": "洪明樂", "method": "interview", "teacherShare": "今天的課程明樂都玩的好開心，能自己幫自己按摩還有體驗卷壽司～長大的好處就是能真的體驗到課程中的樂趣", "parentFeedback": "謝謝老師辛苦了", "createdBy": 330019}, {"id": 1290003, "weekNumber": 17, "date": "2026-04-21", "studentId": 3, "studentName": "張蘊桐", "method": "interview", "teacherShare": "今天的課程芋頭都玩得好開心，能自己為自己按摩還有體驗卷壽司的快樂～真的只有長大才能體驗到課程中的樂趣❤️", "parentFeedback": "謝謝老師～好喜歡知愛家的每個活動課程安排", "createdBy": 330019}, {"id": 1290004, "weekNumber": 17, "date": "2026-04-21", "studentId": 4, "studentName": "李芊樂", "method": "interview", "teacherShare": "今天的課程雖然芊樂會有些害怕，但是他還是在老師的鼓勵下完成了卷壽司課程，每個人都有害怕的事物，但能勇敢嘗試就是最棒的體驗", "parentFeedback": "謝謝老師的陪伴", "createdBy": 330019}, {"id": 1290005, "weekNumber": 17, "date": "2026-04-21", "studentId": 5, "studentName": "黃予希", "method": "interview", "teacherShare": "今天的課程希希都玩得好開心，能為自己按摩還能體驗卷壽司的快樂～果然只有長大才能體驗到課程中的樂趣～", "parentFeedback": "謝謝老師，媽媽看了也好想要玩唷", "createdBy": 330019}, {"id": 1290006, "weekNumber": 17, "date": "2026-04-21", "studentId": 6, "studentName": "吳允希", "method": "interview", "teacherShare": "今天的課程中希希很配合的一起卷了壽司，雖然中間卷完了感到害怕只嘗試了一下下，但值得鼓勵是他跨出了那一步上前體驗的勇氣，非常棒喔！", "parentFeedback": "謝謝老師的鼓勵和陪伴她一起完成", "createdBy": 330019}, {"id": 1290007, "weekNumber": 17, "date": "2026-04-21", "studentId": 7, "studentName": "楊曜任", "method": "interview", "teacherShare": "今天的課程阿弟都玩得好開心，為自己按摩還有體驗卷壽司的快樂～果然只有長大才能體驗到課程中的樂趣❤️", "parentFeedback": "謝謝老師辛苦了", "createdBy": 330019}, {"id": 1290008, "weekNumber": 17, "date": "2026-04-21", "studentId": 8, "studentName": "莊又羽", "method": "interview", "teacherShare": "今天的課程又羽都表現得非常好，為自己按摩體驗卷壽司的快樂，又羽長大了能勇敢的向前體驗課程中的樂趣，表現非常棒呢", "parentFeedback": "謝謝老師的陪伴～", "createdBy": 330019}, {"id": 1290009, "weekNumber": 17, "date": "2026-04-21", "studentId": 9, "studentName": "王鈺棠", "method": "interview", "teacherShare": "今天的課程棠棠害怕精油在他的手上不知如何是好，但他還是很努力聽從老師的指令，完成了為自己按摩～勇敢的踏出了那一步值得被表揚👍", "parentFeedback": "謝謝老師的鼓勵和陪伴，讓棠棠能勇敢去嘗試", "createdBy": 330019}, {"id": 1290010, "weekNumber": 17, "date": "2026-04-21", "studentId": 10, "studentName": "吳承諺", "method": "interview", "teacherShare": "今天的課程諺諺玩得很開心，能為自己按摩和體驗卷壽司的快樂～長大能體會到課程中的樂趣，也能得到更多不一樣的回憶", "parentFeedback": "謝謝老師很喜歡知愛家的課程安排", "createdBy": 330019}, {"id": 1320001, "weekNumber": 17, "date": "2026-04-23", "studentId": 30, "studentName": "陳杏恩", "method": "interview", "teacherShare": "杏恩會用頭靠近同學的頭，對同學笑得很開心，他真的很喜歡書本！", "parentFeedback": "交到好朋友了；在家杏恩看棕色的熊那本，只要翻到老師那頁，他就會很開心，感覺很喜歡老師~下周一回診會晚到中心。", "createdBy": 750001}, {"id": 1320002, "weekNumber": 17, "date": "2026-04-23", "studentId": 32, "studentName": "吳允霏", "method": "interview", "teacherShare": "精神活力非常好，四處爬行，也會想躲到桌子底下，在床午休時，非常喜歡扶站！", "parentFeedback": "明日會幫寶貝準備護膝，再麻煩老師幫他戴；在家也愛扶站。", "createdBy": 750001}, {"id": 1320003, "weekNumber": 17, "date": "2026-04-22", "studentId": 33, "studentName": "黃語則", "method": "interview", "teacherShare": "昨日讓寶貝進行寶寶瑜伽壽司式，也有上寶寶精油按摩，他都情緒穩定地參與，感覺蠻喜歡！今日有幫寶寶拍照則則拿鮮花要送給媽咪。", "parentFeedback": "語則從小就很喜歡精油按摩；壽司式照片好萌；拿鮮花的則則媽媽感覺到愛意滿滿，快被融化了。", "createdBy": 750001}, {"id": 1320004, "weekNumber": 17, "date": "2026-04-24", "studentId": 30001, "studentName": "黃梓芸", "method": "phone", "teacherShare": "午休起床後在地墊玩時，會拆掉自己的手套，有時揮到自己的頭部有點紅痕，老師有特別留意，但他都會繼續開心地探索，笑咪咪地看著老師。", "parentFeedback": "對，他在家也都會自己拆掉手套。", "createdBy": 750001}, {"id": 1320005, "weekNumber": 17, "date": "2026-04-24", "studentId": 34, "studentName": "張語恩", "method": "interview", "teacherShare": "語恩一直在練習翻身，很喜歡跟手偶說話，最近有讓他多坐著進行活動。", "parentFeedback": "他最近比較愛翻身；請老師回家上車前幫語恩換尿布，不然他會一路哭回家；副食品的部分依老師專業判斷，等語恩準備好了再做嘗試。", "createdBy": 750001}, {"id": 1320006, "weekNumber": 17, "date": "2026-04-23", "studentId": 60001, "studentName": "高士鵬", "method": "interview", "teacherShare": "今天奶130cc都有喝完，但是有因為溢奶二而換衣服兩次，也有讓寶貝分兩段喝，多拍嗝。", "parentFeedback": "明日餵奶降低奶量100cc就好，再麻煩老師。", "createdBy": 750001}, {"id": 1350001, "weekNumber": 17, "date": "2026-04-21", "studentId": 21, "studentName": "劉瑀彤", "method": "interview", "teacherShare": "今日上了兩堂小腳老師的課程，卷壽司與精油按摩！瑀彤對自己把自己捲在床墊裡面的感覺感到興奮與好玩之外，就連自己手上沾滿精油後，不管是四肢也好，還是臉部也行，都能讓瑀彤相當捧場與配合，甚至還一直跟老師要精油，可以感受的到瑀彤很喜歡上小腳老師的課唷，真棒！😁😁😁", "parentFeedback": "哈哈，在家如果有這麼配合爸爸媽媽所說的話就好了😅", "createdBy": 1440078}, {"id": 1350002, "weekNumber": 17, "date": "2026-04-21", "studentId": 22, "studentName": "張瑾馨", "method": "interview", "teacherShare": "今日上了兩堂小腳老師的課程，卷壽司與精油按摩！瑾馨對自己把自己捲在床墊裡面的感覺感到興奮與好玩之外，就連自己手上沾滿精油後，不管是四肢也好，還是臉部也行，都能讓瑾馨相當捧場與配合，甚至還一直跟老師要精油，可以感受的到瑾馨很喜歡上小腳老師的課唷，真棒！😁😁😁", "parentFeedback": "越大越有自己的想法，希望別造成老師們的困擾就好xd", "createdBy": 1440078}, {"id": 1350003, "weekNumber": 17, "date": "2026-04-21", "studentId": 23, "studentName": "余硯宸", "method": "interview", "teacherShare": "今日上了兩堂小腳老師的課程，卷壽司與精油按摩！硯宸對自己把自己捲在床墊裡面的感覺感到興奮與好玩之外，就連自己手上沾滿精油後，不管是四肢也好，還是臉部也行，都能讓硯宸相當捧場與配合，甚至還一直跟老師要精油，可以感受的到硯宸很喜歡上小腳老師的課唷，真棒！😁😁😁", "parentFeedback": "哇！能配合小腳老師上完這堂課的硯宸，很不容易哦，辛苦老師們了😁", "createdBy": 1440078}, {"id": 1350004, "weekNumber": 17, "date": "2026-04-21", "studentId": 24, "studentName": "蔡雨彤", "method": "interview", "teacherShare": "今日上了兩堂小腳老師的課程，卷壽司與精油按摩！雨彤對自己把自己捲在床墊裡面的感覺感到興奮與好玩之外，就連自己手上沾滿精油後，不管是四肢也好，還是臉部也行，都能讓雨彤相當捧場與配合，甚至還一直跟老師要精油，可以感受的到雨彤很喜歡上小腳老師的課唷，真棒！😁😁😁", "parentFeedback": "謝謝老師", "createdBy": 1440078}, {"id": 1350005, "weekNumber": 17, "date": "2026-04-21", "studentId": 25, "studentName": "黃映澄", "method": "interview", "teacherShare": "今日上了兩堂小腳老師的課程，卷壽司與精油按摩！澄澄對自己把自己捲在床墊裡面的感覺感到興奮與好玩之外，就連自己手上沾滿精油後，不管是四肢也好，還是臉部也行，都能讓澄澄相當捧場與配合，甚至還一直跟老師要精油，可以感受的到澄澄很喜歡上小腳老師的課唷，真棒！😁😁😁", "parentFeedback": "真的嗎？澄澄卷壽司的時候一點都不害怕嗎？哈哈... 媽媽在家曾經有跟她玩類似的遊戲過，她都害怕的馬上逃離現場🤣", "createdBy": 1440078}, {"id": 1350006, "weekNumber": 17, "date": "2026-04-21", "studentId": 35, "studentName": "賴時儀", "method": "interview", "teacherShare": "今日上了兩堂小腳老師的課程，卷壽司與精油按摩！時儀對自己把自己捲在床墊裡面的感覺感到興奮與好玩之外，就連自己手上沾滿精油後，不管是四肢也好，還是臉部也行，都能讓時儀相當捧場與配合，甚至還一直跟老師要精油，可以感受的到時儀很喜歡上小腳老師的課唷，真棒！😁😁😁", "parentFeedback": "非常不錯的課程與體驗，謝謝老師", "createdBy": 1440078}, {"id": 1350007, "weekNumber": 17, "date": "2026-04-21", "studentId": 90001, "studentName": "陳語湉", "method": "interview", "teacherShare": "今日上了兩堂小腳老師的課程，卷壽司與精油按摩！大福對自己把自己捲在床墊裡面的感覺感到興奮與好玩之外，就連自己手上沾滿精油後，不管是四肢也好，還是臉部也行，都能讓大福相當捧場與配合，甚至還一直跟老師要精油，可以感受的到大福很喜歡上小腳老師的課唷，真棒！😁😁😁", "parentFeedback": "第一次上小腳老師的課就這麼認真呀？！\n在家都到處亂跑xd 老師們辛苦了", "createdBy": 1440078}, {"id": 1350008, "weekNumber": 17, "date": "2026-04-21", "studentId": 26, "studentName": "林逸宸", "method": "interview", "teacherShare": "今日上了兩堂小腳老師的課程，卷壽司與精油按摩！逸宸對自己把自己捲在床墊裡面的感覺感到興奮與好玩之外，就連自己手上沾滿精油後，不管是四肢也好，還是臉部也行，都能讓逸宸相當捧場與配合，甚至還一直跟老師要精油，可以感受的到逸宸很喜歡上小腳老師的課唷，真棒！😁😁😁", "parentFeedback": "哈哈，媽媽腦袋浮現逸宸很多豐富有趣的畫面，謝謝老師們", "createdBy": 1440078}, {"id": 1350009, "weekNumber": 17, "date": "2026-04-21", "studentId": 28, "studentName": "陳品叡", "method": "interview", "teacherShare": "今日上了兩堂小腳老師的課程，卷壽司與精油按摩！可樂對自己把自己捲在床墊裡面的感覺感到興奮與好玩之外，就連自己手上沾滿精油後，不管是四肢也好，還是臉部也行，都能讓可樂相當捧場與配合，甚至還一直跟老師要精油，可以感受的到可樂很喜歡上小腳老師的課唷，真棒！😁😁😁", "parentFeedback": "聽老師這樣說，可樂一定玩得很開心！老師辛苦了", "createdBy": 1440078}, {"id": 1350010, "weekNumber": 17, "date": "2026-04-21", "studentId": 29, "studentName": "林禹順", "method": "interview", "teacherShare": "今日上了兩堂小腳老師的課程，卷壽司與精油按摩！順順對自己把自己捲在床墊裡面的感覺感到興奮與好玩之外，就連自己手上沾滿精油後，不管是四肢也好，還是臉部也行，都能讓順順相當捧場與配合，甚至還一直跟老師要精油，可以感受的到順順很喜歡上小腳老師的課唷，真棒！😁😁😁", "parentFeedback": "哇，這麼豐富多元的課程，順順好幸福呀！謝謝老師們", "createdBy": 1440078}, {"id": 1380001, "weekNumber": 17, "date": "2026-04-24", "studentId": 27, "studentName": "謝知愛", "method": "interview", "teacherShare": "小愛很喜歡在Z班的時候，每天都玩得好開心～～還有學會獨走了幾步，但後面就不走了哈哈", "parentFeedback": "謝謝老師辛苦了", "createdBy": 330019}, {"id": 1410001, "weekNumber": 18, "date": "2026-04-30", "studentId": 1, "studentName": "林品逸", "method": "interview", "teacherShare": "品逸真的是越來越活潑了，看到同學都會很熱情的想和同學接觸，不過有時候會沒有控制好力道，老師會再多多提醒他！", "parentFeedback": "他在家也是這樣很不受控，再麻煩老師多多提醒他了！", "createdBy": 390021}, {"id": 1410002, "weekNumber": 18, "date": "2026-04-30", "studentId": 2, "studentName": "洪明樂", "method": "interview", "teacherShare": "明樂越來越貼心了，看到班上的弟弟妹妹需要幫忙都會去幫忙，還會問弟弟妹妹說你怎麼了，真的是暖男呢！", "parentFeedback": "謝謝老師的分享，明樂真的長大了好多！", "createdBy": 390021}, {"id": 1410003, "weekNumber": 18, "date": "2026-04-30", "studentId": 3, "studentName": "張蘊桐", "method": "interview", "teacherShare": "芋頭最近有和老師反應同學會用到他，那老師也會和芋頭聊聊事情的過程，聊完後芋頭的心情就會好很多，老師也會多多的留意！", "parentFeedback": "芋頭回家後也會分享在學校發生的事，也有提到這件事，再麻煩老師多多留意了，謝謝老師！", "createdBy": 390021}, {"id": 1410004, "weekNumber": 18, "date": "2026-04-30", "studentId": 4, "studentName": "李芊樂", "method": "interview", "teacherShare": "芊樂最近的排便還是不太順暢，老師會讓他多多喝水，多吃水果，也會在多觀察。", "parentFeedback": "謝謝老師，回家後我們也會再多多留意，真的還是沒大便會帶她去看醫生。", "createdBy": 390021}, {"id": 1410005, "weekNumber": 18, "date": "2026-04-30", "studentId": 5, "studentName": "黃予希", "method": "interview", "teacherShare": "予希是個很棒的小幫手，都會幫忙收玩具，看到同學需要幫忙也會和同學說我來幫你，是個大姐姐了呢！", "parentFeedback": "太棒了吧！在家裡也是這樣，很喜歡幫忙爸爸媽媽做事情，長大了好多呢！", "createdBy": 390021}, {"id": 1410006, "weekNumber": 18, "date": "2026-04-30", "studentId": 6, "studentName": "吳允希", "method": "interview", "teacherShare": "希希的表達能力越來越進步囉！不過有時候講話會太快，老師都會提醒他要慢慢說，後面希希就會慢慢說囉！", "parentFeedback": "希希在家也是，我們都常常聽不懂她在說什麼，謝謝老師，辛苦啦！", "createdBy": 390021}, {"id": 1410007, "weekNumber": 18, "date": "2026-04-30", "studentId": 7, "studentName": "楊曜任", "method": "interview", "teacherShare": "曜任現在對於自己便便了會非常的清楚，也會主動的和老師說，之後會嘗試讓他坐馬桶喔！", "parentFeedback": "再麻煩老師慢慢的教他了，謝謝老師，辛苦了！", "createdBy": 390021}, {"id": 1410008, "weekNumber": 18, "date": "2026-04-28", "studentId": 8, "studentName": "莊又羽", "method": "interview", "teacherShare": "又羽的情緒最近有開始比較穩定了，只不過有時候想到爸爸媽媽還是會有情緒，不過有她最愛的被被陪著她就OK囉！", "parentFeedback": "她真的很愛那條被被，假日出門也都要帶著，不然她也會有小情緒～", "createdBy": 390021}, {"id": 1410009, "weekNumber": 18, "date": "2026-04-30", "studentId": 9, "studentName": "王鈺棠", "method": "interview", "teacherShare": "棠棠真的很愛玩車車，每次一到中心第一件事就是找車車玩，看到同學在玩車車還會一直看著人家玩，真的很有趣呢！", "parentFeedback": "棠棠在家裡也是，有滿滿的車車給他玩，有時候請他把車車收起來還會跟我們生氣呢，真是有個性的小孩！", "createdBy": 390021}, {"id": 1410010, "weekNumber": 18, "date": "2026-04-30", "studentId": 10, "studentName": "吳承諺", "method": "interview", "teacherShare": "諺諺真的是一個非常活潑的孩子，有時候都會坐不住，老師都會提醒他，提醒他後他就能坐好囉！", "parentFeedback": "諺諺就是一個很活潑的孩子，在家裡也是都跟哥哥衝來衝去，辛苦老師了！", "createdBy": 390021}, {"id": 1410011, "weekNumber": 18, "date": "2026-04-30", "studentId": 27, "studentName": "謝知愛", "method": "phone", "teacherShare": "知愛真的是個小吃貨呢！吃飯吃的很非常好，老師餵的太慢還會發出可愛的聲音叫老師趕快餵她吃下一口呢！", "parentFeedback": "知愛在吃的部分真的是最不用擔心的，繼續吃好吃滿長肉肉吧！", "createdBy": 390021}, {"id": 1440001, "weekNumber": 18, "date": "2026-04-29", "studentId": 30, "studentName": "陳杏恩", "method": "interview", "teacherShare": "杏恩真的非常喜歡書本呢！他進教室後，會先去拿書看，對於浮貼頁他會主動翻。", "parentFeedback": "他每天晚上睡前都會跟我們一起看書，看親愛的動物園那本時，他也很喜歡翻那個浮貼頁。", "createdBy": 750001}, {"id": 1470001, "weekNumber": 18, "date": "2026-04-28", "studentId": 60001, "studentName": "高士鵬", "method": "interview", "teacherShare": "今天讓鵬鵬進行母親節活動照顧寶寶的課程，抱著他一起餵奶、哄睡，讓寶貝感受被愛的氛圍。", "parentFeedback": "謝謝老師用心準備", "createdBy": 750001}, {"id": 1470002, "weekNumber": 18, "date": "2026-04-28", "studentId": 33, "studentName": "黃語則", "method": "phone", "teacherShare": "媽媽寶貝藥袋內僅有兩包藥粉，餵藥委託單上寫在中心要餵三次藥粉+藥水，請問媽咪第三餐奶後只有剩藥水，沒有藥粉了，仍然要餵藥水嗎？寶貝精神活力都還不錯！", "parentFeedback": "第三餐奶後的藥，先不要餵了，晚上可能會再帶去看醫生。", "createdBy": 750001}, {"id": 1500001, "weekNumber": 18, "date": "2026-04-29", "studentId": 34, "studentName": "張語恩", "method": "interview", "teacherShare": "語恩開始初次嘗試副食品，會主動張開嘴巴，也有吞嚥，對於高麗菜口味也能接受，雖然坐幫寶椅一陣子頭身體會歪斜，但整體來說，吃得很不錯！", "parentFeedback": "醫師說他容易溢奶，體型偏瘦小，建議開始加入副食品，再麻煩老師了；我週末回家也會做副食品給他吃。", "createdBy": 750001}, {"id": 1500002, "weekNumber": 18, "date": "2026-04-29", "studentId": 32, "studentName": "吳允霏", "method": "interview", "teacherShare": "允霏有七顆牙齒了，最近長了很多顆，本週開始讓允霏帶牙刷來，養成清潔牙齒的習慣，老師會慢慢引導協助他。最近吃飯時，非常喜歡咬住湯匙。", "parentFeedback": "謝謝老師，對，他之前就會，湯匙上都有咬痕。", "createdBy": 750001}, {"id": 1530001, "weekNumber": 18, "date": "2026-04-29", "studentId": 30001, "studentName": "黃梓芸", "method": "interview", "teacherShare": "這幾天寶貝有流鼻涕的狀況，有幫他吸鼻涕，精神活力很好，非常喜歡翻身；臉部與腳每日都有幫他擦乳液，臉部有時日仍容易紅。", "parentFeedback": "鼻涕較多，再麻煩老師了。我們在家也都會幫他勤擦乳液。", "createdBy": 750001}, {"id": 1560001, "weekNumber": 18, "date": "2026-04-30", "studentId": 21, "studentName": "劉瑀彤", "method": "interview", "teacherShare": "瑀彤最近會把自己的被子套在頭上跟同學玩躲貓貓，同學跟著她一起套頭上，玩到一半太開心時，還會一起拍手說好棒，畫面實在太有趣了", "parentFeedback": "真的是名副其實的里長母欸，帶頭作亂xd", "createdBy": 1440078}, {"id": 1560002, "weekNumber": 18, "date": "2026-04-30", "studentId": 22, "studentName": "張瑾馨", "method": "interview", "teacherShare": "瑾馨最近心情很好，午休起來會自己邊唱歌邊拍手，甚至還站起來邀約隔壁同學一起唱，唱完還會拍手說：耶~~~   太可愛了吧♥️", "parentFeedback": "調皮，不知道有沒有吵到其他同學休息xd", "createdBy": 1440078}, {"id": 1560003, "weekNumber": 18, "date": "2026-04-30", "studentId": 23, "studentName": "余硯宸", "method": "interview", "teacherShare": "硯宸最近好喜歡撒嬌，只要有跟老師近距離接觸的活動期間，就一定會跑來坐在老師身上，並且分享他手上的玩具，好貼心哦🥰", "parentFeedback": "硯宸就是個活寶，每天都很期待去學校，謝謝老師的照顧", "createdBy": 1440078}, {"id": 1560004, "weekNumber": 18, "date": "2026-04-30", "studentId": 24, "studentName": "蔡雨彤", "method": "interview", "teacherShare": "雨彤最近在跟同學玩的時候，會有搶玩具的情形，老師看到立即制止並引導她這樣是不對的行為後，雨彤就馬上拿玩具分享給同學，很棒", "parentFeedback": "謝謝老師", "createdBy": 1440078}, {"id": 1560005, "weekNumber": 18, "date": "2026-04-30", "studentId": 25, "studentName": "黃映澄", "method": "interview", "teacherShare": "澄澄最近不開心的時候會有咬人的動作出現，而且還會加上吼叫聲，老師看到立即制止並安撫她情緒後，引導她這是不對的行為！再麻煩家長一起觀察澄澄平常在家是否也會有此行為，謝謝！", "parentFeedback": "澄澄目前在家沒有這樣的行為，我們會引導她這樣是不對的行為，老師辛苦了", "createdBy": 1440078}, {"id": 1560006, "weekNumber": 18, "date": "2026-04-30", "studentId": 35, "studentName": "賴時儀", "method": "interview", "teacherShare": "時儀最近活動力十足耶，跟同學在玩的時候會開心的蹦蹦跳跳，發現老師在看她的時候還會對著老師傻笑，然後默默的繼續蹦蹦跳跳，太可愛了🤣", "parentFeedback": "哈哈，時儀在家有時也會這麼突然的到處跑到處玩，爸爸媽媽偶爾會抓不住她xd", "createdBy": 1440078}, {"id": 1560007, "weekNumber": 18, "date": "2026-04-30", "studentId": 90001, "studentName": "陳語湉", "method": "interview", "teacherShare": "大福入托一個月了，適應得很好唷！每天來到中心都笑瞇瞇的，除了中午吃飯前會著急的要吃而有點小哭哭，但老師都會安撫她，並引導她要慢慢咬再吞下去，她聽完老師說的話，都會笑笑的回應老師，超可愛的♥️", "parentFeedback": "大福對吃很感興趣，什麼都可以慢慢的，唯獨吃就是要這麼霸氣，哈哈！辛苦老師了", "createdBy": 1440078}, {"id": 1560008, "weekNumber": 18, "date": "2026-04-30", "studentId": 26, "studentName": "林逸宸", "method": "interview", "teacherShare": "逸宸最近不知道是褲子太長還是會熱，老師幫他穿好後過沒多久，逸宸都會自己把褲子蹭掉，兩隻白嫩嫩的雙腳就亮出來給老師欣賞，再麻煩家長在家一起觀察逸宸是否也有這樣的情形，謝謝", "parentFeedback": "逸宸在家有時也會，爸爸媽媽會多多引導他不要這樣子，謝謝老師，辛苦了", "createdBy": 1440078}, {"id": 1560009, "weekNumber": 18, "date": "2026-04-30", "studentId": 28, "studentName": "陳品叡", "method": "interview", "teacherShare": "可樂最近午休的時候會自己跟自己玩了一時半會兒後才斷電，老師一開始拍睡加哄睡他都不要勒，自己要自己醞釀睡意後才要睡，呵呵！可愛", "parentFeedback": "調皮的可樂，耍個性哦xd", "createdBy": 1440078}, {"id": 1560010, "weekNumber": 18, "date": "2026-04-30", "studentId": 29, "studentName": "林禹順", "method": "interview", "teacherShare": "順順最近很喜歡爬到桌邊站著，兩眼到處看了看之後，雙手開始拍打著桌子，開心的笑出聲音，老師在他後面護著他的同時，都會被他開心快樂的模樣也逗樂了，超可愛勒🥰", "parentFeedback": "哈哈，順順這麼搞怪啊？在家都不會這樣，偶包有點重喔🤣", "createdBy": 1440078}, {"id": 1590001, "weekNumber": 17, "date": "2026-04-21", "studentId": 11, "studentName": "葉紫婕", "method": "phone", "teacherShare": "最近在中心都會主動收玩具，也會自己唱兒歌", "parentFeedback": "最近在家裡也都會唱兒歌，尤其是大象這首歌", "createdBy": 1590028}, {"id": 1590002, "weekNumber": 17, "date": "2026-04-21", "studentId": 12, "studentName": "陳奕睿", "method": "phone", "teacherShare": "最近在中心都會主動收玩具，也喜歡隨著歌跳舞，更喜歡幫忙老師整理東西", "parentFeedback": "最近在家中也都會想要幫父母拿東西越來越勤勞，真的很棒", "createdBy": 1590028}, {"id": 1590003, "weekNumber": 17, "date": "2026-04-21", "studentId": 13, "studentName": "許睿桓", "method": "phone", "teacherShare": "最近睡覺時間有慢慢可以延後到快吃飯的時候，持續觀察中", "parentFeedback": "最近在家中也都會到快要11點多才想睡覺，老師建議的方式蠻有效果的，謝謝", "createdBy": 1590028}, {"id": 1590004, "weekNumber": 17, "date": "2026-04-21", "studentId": 14, "studentName": "蘇彥澄", "method": "phone", "teacherShare": "最近在學校也都會認真地幫老師收東西，而且都會主動想要幫老師做點什麼事情真的很棒", "parentFeedback": "最近在家裡都會主動和父母說很多很多的話，連老師在學校教的中文和英文都會突然脫口而出", "createdBy": 1590028}, {"id": 1590005, "weekNumber": 17, "date": "2026-04-21", "studentId": 15, "studentName": "李澪", "method": "phone", "teacherShare": "最近在學校和同學的相處上越來越熱絡，也比較不會那麼怕生", "parentFeedback": "在家裡表現得非常的開心，希望在學校也可以越來越進步", "createdBy": 1590028}, {"id": 1590006, "weekNumber": 17, "date": "2026-04-21", "studentId": 16, "studentName": "余承澔", "method": "phone", "teacherShare": "最近在學校偶爾還是會出現稍微推擠同學的行為，持續引導中", "parentFeedback": "謝謝老師們的引導，父母在家裡也會好好的跟小朋友說行為Nono的時候該怎麼去面對", "createdBy": 1590028}, {"id": 1590007, "weekNumber": 17, "date": "2026-04-21", "studentId": 17, "studentName": "陳禹澔", "method": "phone", "teacherShare": "最近在學校下午都吃的非常的多，奶量大約都在160c.c.上下", "parentFeedback": "最近在家裡食欲都非常得好，希望副食也可以自己吃的越來越棒", "createdBy": 1590028}, {"id": 1590008, "weekNumber": 17, "date": "2026-04-21", "studentId": 18, "studentName": "彭翊宸", "method": "phone", "teacherShare": "最近在學校拉扯同學的行為有越來越減少，看到老師引導時也都會再重複一次輕輕的動作", "parentFeedback": "謝謝老師們的引導，如果有帶去外面玩也都會持續引導", "createdBy": 1590028}, {"id": 1590009, "weekNumber": 17, "date": "2026-04-21", "studentId": 19, "studentName": "林冠邦", "method": "phone", "teacherShare": "最近在學校越來越聽得懂老師們的指令，希望會越來越進步加油", "parentFeedback": "在家裡也都會配合老師說的做學習引導，但小朋友有時候有點調皮，持續加油中", "createdBy": 1590028}, {"id": 1590010, "weekNumber": 17, "date": "2026-04-21", "studentId": 20, "studentName": "蔡禾悅", "method": "phone", "teacherShare": "最近在學校情緒上大多時候也都蠻平穩的，偶爾午休起來時會有點情緒高漲，但在老師的陪伴下可恢復心情平和", "parentFeedback": "在家裡遇到不如意的事情時，也都會突然有情緒，家裡的長輩都能理解，感覺到很欣慰", "createdBy": 1590028}, {"id": 1590011, "weekNumber": 18, "date": "2026-04-29", "studentId": 11, "studentName": "葉紫婕", "method": "phone", "teacherShare": "最近在學校自主用餐的情況有越來越改善，也和父母確認了小朋友確實是使用左手吃飯會比較順利", "parentFeedback": "感謝老師們的陪伴與引導父母本身也都是左撇子", "createdBy": 1590028}, {"id": 1590012, "weekNumber": 18, "date": "2026-04-29", "studentId": 12, "studentName": "陳奕睿", "method": "interview", "teacherShare": "最近在學校學習的方式比較多元，透過圖書、遊戲、大自然等方式來學習", "parentFeedback": "謝謝老師們的用心教導，小朋友的學習效果真的越來越棒", "createdBy": 1590028}, {"id": 1590013, "weekNumber": 18, "date": "2026-04-29", "studentId": 13, "studentName": "許睿桓", "method": "interview", "teacherShare": "在學校偶爾早餐來的時候，比較沒有辦法耐心等待，會慢慢引導等待的重要性", "parentFeedback": "在家裡也會慢慢讓小朋友學習等待", "createdBy": 1590028}, {"id": 1590014, "weekNumber": 18, "date": "2026-04-29", "studentId": 14, "studentName": "蘇彥澄", "method": "interview", "teacherShare": "最近在學校都會主動和老師問東西的名稱，也都會自己複誦好幾次", "parentFeedback": "最近在家裡也都會一直出現老師們提的詞彙，也都會一直和爸媽介紹中心的同學有哪些", "createdBy": 1590028}, {"id": 1590015, "weekNumber": 18, "date": "2026-04-29", "studentId": 15, "studentName": "李澪", "method": "interview", "teacherShare": "最近在學校戶外活動的時候比較減少哭泣的時間，很開心小朋友可以專心在自由探索的這件事情上很棒喔", "parentFeedback": "假日也都會增加帶小朋友出門的時間，希望會越來越進步", "createdBy": 1590028}, {"id": 1590016, "weekNumber": 18, "date": "2026-04-29", "studentId": 16, "studentName": "余承澔", "method": "interview", "teacherShare": "在學校和同學的相處上雖然偶爾還是會出現搶玩具和推的行為，但是這週明顯的進步很多，老師請小朋友將手放開時，也都可以慢慢做到", "parentFeedback": "感謝老師們的用心引導，在家裡我們也都會很努力地和小朋友說哪些行為是不好的，希望小朋友會越來越進步", "createdBy": 1590028}, {"id": 1590017, "weekNumber": 18, "date": "2026-04-29", "studentId": 17, "studentName": "陳禹澔", "method": "interview", "teacherShare": "最近在學校都能依老師的指令做得越來越好，也和同學的相處互動上越來越多多元", "parentFeedback": "在家裡和家中長輩的互動也越來越多元化，希望會越來越進步喔", "createdBy": 1590028}, {"id": 1590018, "weekNumber": 18, "date": "2026-04-29", "studentId": 18, "studentName": "彭翊宸", "method": "interview", "teacherShare": "在學校和同學的相處上有越來越進步，吃飯的這件事情依然還在努力學習中", "parentFeedback": "在家裡吃飯也都會有點不專心，持續引導中", "createdBy": 1590028}, {"id": 1590019, "weekNumber": 18, "date": "2026-04-29", "studentId": 19, "studentName": "林冠邦", "method": "interview", "teacherShare": "在學校觀察到同學和小朋友的互動越來越多元，但專注度還在努力學習中", "parentFeedback": "在家裡也發現有時候小朋友的專心度沒有很好，持續努力引導中希望會越來越進步", "createdBy": 1590028}, {"id": 1590020, "weekNumber": 18, "date": "2026-04-29", "studentId": 20, "studentName": "蔡禾悅", "method": "interview", "teacherShare": "最近在學校和同學們的互動越來越多元，到戶外活動時也比較能接受，越來越進步喔", "parentFeedback": "謝謝老師們的用心陪伴與引導，假日也都會依照老師的建議多帶小朋友出去戶外活動", "createdBy": 1590028}, {"id": 1620001, "weekNumber": 19, "date": "2026-05-04", "studentId": 21, "studentName": "劉瑀彤", "method": "interview", "teacherShare": "最近發現瑀彤會躲進床墊地下，把自己藏得很隱密，然後偷看大家有沒有發現她，被發現的時候笑得好大聲，怎麼可以這麼可愛啦🤣", "parentFeedback": "哈哈！爸爸在家都跟她這樣玩躲貓貓，原來在學校也會這樣跟同學玩呀....😁😁", "createdBy": 1440078}, {"id": 1650001, "weekNumber": 19, "date": "2026-05-06", "studentId": 30001, "studentName": "黃梓芸", "method": "phone", "teacherShare": "媽咪早安，梓芸書包有藥物，但沒有餵藥委託單，請問梓芸需要吃藥嗎？", "parentFeedback": "需要餵藥，餵藥委託單的內容全部跟昨天餵藥委託單一樣，再請老師協助，晚上我會補簽名。", "createdBy": 750001}, {"id": 1650002, "weekNumber": 19, "date": "2026-05-04", "studentId": 30, "studentName": "陳杏恩", "method": "phone", "teacherShare": "上回統計母親節回條時，媽咪說5/8那周帶杏恩出國，請問是哪天開始請假？何時回來上課？", "parentFeedback": "今天就不會過去上課，要等到下周一杏恩才會返校，要帶他出國。", "createdBy": 750001}, {"id": 1650003, "weekNumber": 19, "date": "2026-05-06", "studentId": 32, "studentName": "吳允霏", "method": "interview", "teacherShare": "允霏最近很喜歡發爸爸的聲音，會一直說爸爸爸爸，邊說邊笑得很開心！也很喜歡練習扶站！", "parentFeedback": "對，他在家裡也會一直說唷，快要叫爸爸了！", "createdBy": 750001}, {"id": 1650004, "weekNumber": 19, "date": "2026-05-06", "studentId": 33, "studentName": "黃語則", "method": "interview", "teacherShare": "老師今日幫他換七條口水巾，他一流口水,老師就馬上幫他擦乾；冷氣也開最涼；乳液也按時抹，但是他的脖子仍然有點微紅，可能是要長牙齒，口水分泌較多，媽咪可以幫他準備固齒器讓他咬。", "parentFeedback": "我今晚會把家裡所有的口水巾及手帕都塞進書包，讓他帶來，再麻煩老師了，也會幫他準備固齒器。", "createdBy": 750001}, {"id": 1650005, "weekNumber": 19, "date": "2026-05-07", "studentId": 34, "studentName": "張語恩", "method": "interview", "teacherShare": "語恩參與活動情緒都蠻穩定；吃副食品時，如果遇到沒有想睡覺狀況，基本上都吃蠻好的，也能接受紅蘿蔔口味。", "parentFeedback": "他在家吃副食品，吃一吃會生氣，不像在中心這麼乖。", "createdBy": 750001}, {"id": 1650006, "weekNumber": 19, "date": "2026-05-08", "studentId": 60001, "studentName": "高士鵬", "method": "interview", "teacherShare": "鵬鵬體驗寶寶瑜伽：小飛機式,他情緒平穩的參與全程；玩搖搖馬和溜滑梯，他也都不害怕，情緒穩定體驗，很棒！", "parentFeedback": "小肥鵬越來越愛去學校，謝謝老師用心教導，請老師多讓鵬鵬轉左邊睡，看左邊，他都習慣轉右邊；奶量也請老師調整為三小時一次，每次120cc。下週一到五由姨姨接送上下學。", "createdBy": 750001}, {"id": 1680001, "weekNumber": 19, "date": "2026-05-08", "studentId": 22, "studentName": "張瑾馨", "method": "interview", "teacherShare": "這次的母親節活動，真的是既感人又相當有回憶的耶，值得珍藏！看著瑾馨端著茶水，一路走向媽咪，給媽咪奉茶加洗腳腳的過程，老師在旁看得是相當感動，媽咪真的很偉大!！\n謝謝瑾馨媽咪撥空來參與知愛家的母親節活動，祝媽咪母親節快樂♥️", "parentFeedback": "謝謝老師，辛苦了", "createdBy": 1440078}, {"id": 1680002, "weekNumber": 19, "date": "2026-05-08", "studentId": 23, "studentName": "余硯宸", "method": "interview", "teacherShare": "這次的母親節活動，真的是既感人又相當有回憶的耶，值得珍藏！雖然硯宸端著茶水，一路走向媽咪，給媽咪奉茶加洗腳腳的過程中，哭到一個不行，但最終還是有順利完成任務，很棒！老師在旁看得是相當感動，媽咪真的很偉大!！\n謝謝硯宸爸比媽咪撥空來參與知愛家的母親節活動，祝媽咪母親節快樂♥️", "parentFeedback": "老師辛苦了！謝謝", "createdBy": 1440078}, {"id": 1680003, "weekNumber": 19, "date": "2026-05-08", "studentId": 24, "studentName": "蔡雨彤", "method": "interview", "teacherShare": "雨彤實在太可愛了，放學時一拿到母親節卡片就想趕快拿回家跟爸爸媽媽分享，這麼小年紀就知道媽媽的偉大，迫不及待想對媽媽送母親節卡片，真的很可愛！祝雨彤媽咪母親節快樂", "parentFeedback": "謝謝老師", "createdBy": 1440078}, {"id": 1680004, "weekNumber": 19, "date": "2026-05-08", "studentId": 25, "studentName": "黃映澄", "method": "interview", "teacherShare": "這次的母親節活動，真的是既感人又相當有回憶的耶，值得珍藏！雖然澄澄從端茶水，一路走向媽咪，給媽咪奉茶加洗腳腳的過程都在哭哭，但最後還是有爸爸的陪伴下，順利完成任務，很棒！老師在旁看得是相當感動，媽咪真的很偉大!！\n謝謝澄澄爸比媽咪撥空來參與知愛家的母親節活動，祝媽咪母親節快樂♥️", "parentFeedback": "那部影片真的太好哭了，謝謝老師們的用心，辛苦了", "createdBy": 1440078}, {"id": 1680005, "weekNumber": 19, "date": "2026-05-08", "studentId": 35, "studentName": "賴時儀", "method": "interview", "teacherShare": "這次的母親節活動，真的是既感人又相當有回憶的耶，值得珍藏！看著時儀端著茶水，一路走向媽咪，給媽咪奉茶加洗腳腳的過程，老師在旁看得是相當感動，媽咪真的很偉大!！\n謝謝時儀媽咪撥空來參與知愛家的母親節活動，祝媽咪母親節快樂♥️", "parentFeedback": "謝謝老師，這活動辦得很好！", "createdBy": 1440078}, {"id": 1680006, "weekNumber": 19, "date": "2026-05-08", "studentId": 90001, "studentName": "陳語湉", "method": "interview", "teacherShare": "這次的母親節活動，真的是既感人又相當有回憶的耶，值得珍藏！看著湉湉端著茶水，一路走向媽咪，給媽咪奉茶加洗腳腳的過程，老師在旁看得是相當感動，媽咪真的很偉大!！\n謝謝湉湉媽咪撥空來參與知愛家的母親節活動，祝媽咪母親節快樂♥️", "parentFeedback": "謝謝老師精心準備的活動！媽媽很感動，辛苦了", "createdBy": 1440078}, {"id": 1680007, "weekNumber": 19, "date": "2026-05-08", "studentId": 26, "studentName": "林逸宸", "method": "interview", "teacherShare": "逸宸真的很可愛，一拿到母親節卡片的當下，差點就被分屍了，哈哈哈！還好在放學前逸宸有撐住，沒有將卡片給毀了，哈哈！祝逸宸媽咪母親節快樂", "parentFeedback": "哈哈，逸宸就是好奇寶寶！謝謝老師的祝福", "createdBy": 1440078}, {"id": 1680008, "weekNumber": 19, "date": "2026-05-08", "studentId": 28, "studentName": "陳品叡", "method": "interview", "teacherShare": "這次的母親節活動，真的是既感人又相當有回憶的耶，值得珍藏！老師牽著可樂端著茶水，一路走向媽咪，給媽咪奉茶加洗腳腳的過程，老師在旁看得是相當感動，媽咪真的很偉大!！\n謝謝可樂媽咪撥空來參與知愛家的母親節活動，祝媽咪母親節快樂♥️", "parentFeedback": "謝謝老師，辛苦了", "createdBy": 1440078}, {"id": 1680009, "weekNumber": 19, "date": "2026-05-08", "studentId": 29, "studentName": "林禹順", "method": "interview", "teacherShare": "這次的母親節活動，真的是既感人又相當有回憶的耶，值得珍藏！雖然順順端著茶水，一路走向媽咪，給媽咪奉茶加洗腳腳的過程有哭哭，但有爸爸的陪伴下，最後有順利完成任務，很棒！！老師在旁看得是相當感動，媽咪真的很偉大!！\n謝謝順順爸比媽咪撥空來參與知愛家的母親節活動，祝媽咪母親節快樂♥️", "parentFeedback": "謝謝老師，辛苦了", "createdBy": 1440078}, {"id": 1710001, "weekNumber": 19, "date": "2026-05-06", "studentId": 1, "studentName": "林品逸", "method": "interview", "teacherShare": "品逸這週觀察下來比較坐的住，可能是擔心爸爸把他的玩具拿來學校與同學分享，所以坐得特別好😂", "parentFeedback": "看來玩具分享有用，再麻煩老師多多提醒他要坐好了！", "createdBy": 390021}, {"id": 1710002, "weekNumber": 19, "date": "2026-05-06", "studentId": 2, "studentName": "洪明樂", "method": "interview", "teacherShare": "明樂表達的方式越來越清楚了喔！之前會講話講太快導致老師聽不太懂他在說什麼，但現在講話變得慢慢說，也更清楚了呢！真棒！", "parentFeedback": "真的嗎！！那真是太好了，明樂在家裡也是講話講的好快，我們也會再多多引導他的！", "createdBy": 390021}, {"id": 1710003, "weekNumber": 19, "date": "2026-05-06", "studentId": 3, "studentName": "張蘊桐", "method": "interview", "teacherShare": "蘊桐早上來會和老師說想大便，老師就會請她到小便盆大便，不過蘊桐後面都只會有尿尿，老師會再多多觀察.引導她！", "parentFeedback": "謝謝老師，在家裡我們也會一起協助引導蘊桐！", "createdBy": 390021}, {"id": 1710004, "weekNumber": 19, "date": "2026-05-06", "studentId": 4, "studentName": "李芊樂", "method": "interview", "teacherShare": "芊樂這幾天在學校都沒有排便，但是身體沒有什麼不舒服的症狀，再請爸爸媽媽回家再觀察看看，辛苦了！", "parentFeedback": "芊樂在家偶爾也不會大便，謝謝老師我們會再多觀察的，辛苦了！", "createdBy": 390021}, {"id": 1710005, "weekNumber": 19, "date": "2026-05-06", "studentId": 5, "studentName": "黃予希", "method": "interview", "teacherShare": "予希每天都是活力滿滿呢！不管是剛到中心還是活動過程，她都會非常熱情的回應老師和同學，真棒！", "parentFeedback": "太棒了，予希真棒！每天早上都吵著要趕快出門，她真的很喜歡知愛家呢！", "createdBy": 390021}, {"id": 1710006, "weekNumber": 19, "date": "2026-05-06", "studentId": 6, "studentName": "吳允希", "method": "interview", "teacherShare": "允希是我們班的小歌后呢！每天來到中心後就一直唱個兒歌，完全唱不停，發現老師在看著她，她就會害羞的看著老師笑，真的很可愛呢！", "parentFeedback": "她真的是每天都活力滿滿，回家後也是，感覺怎麼唱怎麼玩都不累的感覺！", "createdBy": 390021}, {"id": 1710007, "weekNumber": 19, "date": "2026-05-06", "studentId": 7, "studentName": "楊曜任", "method": "interview", "teacherShare": "曜任進步了好多，之前請他坐在椅子上都坐不住，現在只要老師多多提醒他他就能坐的住了，加油！繼續保持！", "parentFeedback": "曜任在家裡也是，都要姐姐來治他，謝謝老師，辛苦了！", "createdBy": 390021}, {"id": 1710008, "weekNumber": 19, "date": "2026-05-06", "studentId": 8, "studentName": "莊又羽", "method": "interview", "teacherShare": "又羽回國後情緒有稍稍的不太穩定，不過有被被陪著她她就好多了呢！", "parentFeedback": "再請老師多多觀察了，又羽每次隔好多天沒去中心好像就會這樣！", "createdBy": 390021}, {"id": 1710009, "weekNumber": 19, "date": "2026-05-08", "studentId": 9, "studentName": "王鈺棠", "method": "interview", "teacherShare": "鈺棠生日快樂！時間真快！今天滿兩歲了，棠棠也進步了好多，尤其是語言發展的部分，越來越進步了，講話越來越清楚囉！", "parentFeedback": "時間真快，棠棠兩歲了！時間真的不等人，我們也有發現他語言能力進步了好多，老師辛苦了！", "createdBy": 390021}, {"id": 1710010, "weekNumber": 19, "date": "2026-05-06", "studentId": 10, "studentName": "吳承諺", "method": "interview", "teacherShare": "承諺這幾天還是有一些感冒的症狀，不過沒有影響到他的活動力和食慾喔！老師會在多多觀察！", "parentFeedback": "謝謝老師，這週會再帶承諺回診所看一下感冒的狀況！", "createdBy": 390021}, {"id": 1710011, "weekNumber": 19, "date": "2026-05-06", "studentId": 27, "studentName": "謝知愛", "method": "interview", "teacherShare": "知愛現在越來越坐不住了！真的是長大了有差😂😂不過老師抱她回去坐好後她就能坐好一下子，一起慢慢進步吧！", "parentFeedback": "知愛真的長大了，在家裡每天這樣看她也覺得長大的好快呢！", "createdBy": 390021}, {"id": 1740001, "weekNumber": 19, "date": "2026-05-04", "studentId": 11, "studentName": "葉紫婕", "method": "interview", "teacherShare": "目前在學校都可以自行用餐，且都可以依老師的指示去執行任務越做越棒喔", "parentFeedback": "目前在家裡也都可以依家長的指令去執行正確的事情，做錯事情的時候也都會給予正確的引導喔", "createdBy": 1590028}, {"id": 1740002, "weekNumber": 19, "date": "2026-05-04", "studentId": 12, "studentName": "陳奕睿", "method": "interview", "teacherShare": "目前在學校都可以越來越適應戶外活動的過程和遊戲內容，希望往後出去戶外活動也能越來越適應", "parentFeedback": "目前假日也都會盡量帶小朋友出去戶外走走", "createdBy": 1590028}, {"id": 1740003, "weekNumber": 19, "date": "2026-05-04", "studentId": 13, "studentName": "許睿桓", "method": "interview", "teacherShare": "目前在學校作息時間有越來越規律，關於睡眠時間比較長一些的部分也有慢慢再改善", "parentFeedback": "目前在家裡也都會盡量配合學校的生活作息", "createdBy": 1590028}, {"id": 1740004, "weekNumber": 19, "date": "2026-05-04", "studentId": 14, "studentName": "蘇彥澄", "method": "interview", "teacherShare": "目前在學校都能夠自己和老師們聊天，不再是三個字或兩個字的詞字，而是能完成自己獨立的一句話", "parentFeedback": "目前在家家裡也都有盡量的和小朋友做溝通，也有發現語言進步的越來越神速", "createdBy": 1590028}, {"id": 1740005, "weekNumber": 19, "date": "2026-05-04", "studentId": 15, "studentName": "李澪", "method": "interview", "teacherShare": "目前在學校的活動時間都有越來越適應和其他小朋友的互動也越來越和諧，希望能越來越進步", "parentFeedback": "家長有回饋說在家裡也都會盡量和小朋友練習說中文", "createdBy": 1590028}, {"id": 1740006, "weekNumber": 19, "date": "2026-05-04", "studentId": 16, "studentName": "余承澔", "method": "interview", "teacherShare": "目前在學校和同學之間的互動，如果有遇到搶玩具或者是推及的行為出現，也都能依照老師的引導下慢慢地做出改善", "parentFeedback": "目前在家裡爸爸和媽媽也都會努力地和小朋友做引導和溝通，謝謝老師們的用心辛苦了", "createdBy": 1590028}, {"id": 1740007, "weekNumber": 19, "date": "2026-05-04", "studentId": 17, "studentName": "陳禹澔", "method": "interview", "teacherShare": "目前在學校都會自己和老師們做聊天室的互動，和同學之間的遊戲相處上也越來越有邏輯性", "parentFeedback": "目前在家裡有發現小朋友會自己和父母創造獨立的句子做對話式溝通，似乎語言發展上越來越進步喔", "createdBy": 1590028}, {"id": 1740008, "weekNumber": 19, "date": "2026-05-04", "studentId": 18, "studentName": "彭翊宸", "method": "phone", "teacherShare": "這一週都請病假，已有打電話和家長做聯絡以及關心小朋友的狀況", "parentFeedback": "這一週有去醫院做治療，謝謝老師們的用心和關心，希望小朋友會盡早康復喔", "createdBy": 1590028}, {"id": 1740009, "weekNumber": 19, "date": "2026-05-04", "studentId": 19, "studentName": "林冠邦", "method": "interview", "teacherShare": "目前在學校如果小朋友有做比較危險的事情時，老師們都會給予正確的引導方式，小朋友也都會越來越努力嘗試去改善並做得更好", "parentFeedback": "目前在家裡爸爸和媽媽也都很用心的和小朋友做引導，也發現小朋友越來越難，依照老師說的建議去慢慢做改善，謝謝老師們的用心引導", "createdBy": 1590028}, {"id": 1740010, "weekNumber": 19, "date": "2026-05-04", "studentId": 20, "studentName": "蔡禾悅", "method": "interview", "teacherShare": "目前和小朋友之間的互動以及出去外面做戶外活動時的反應都有越來越進步，相較於之前情緒較敏感的情況來說真的進步很多喔", "parentFeedback": "謝謝老師們的用心與及建議目前在家裡都會增加讓小朋友接觸敏感性的事物以及多多出去戶外走走", "createdBy": 1590028}, {"id": 1740011, "weekNumber": 20, "date": "2026-05-12", "studentId": 11, "studentName": "葉紫婕", "method": "interview", "teacherShare": "目前在學校有時候會出現推及同學的行為或是咬同學的情況發生，但是經過老師們的引導相信小朋友會越來越進步喔", "parentFeedback": "謝謝老師們的協助，相信小朋友在自由探索和自主摸索的情況下都能夠越來越進步", "createdBy": 1590028}, {"id": 1740012, "weekNumber": 20, "date": "2026-05-12", "studentId": 12, "studentName": "陳奕睿", "method": "interview", "teacherShare": "目前有一些感冒的症狀，持續觀察中，流鼻涕的情況少量透明，但午休時咳嗽的情形比較嚴重一些", "parentFeedback": "目前在家裡也有些微的感冒症狀，目前也還在持續觀察中，如果有越來越嚴重會帶去看醫生，謝謝老師們的關心", "createdBy": 1590028}, {"id": 1740013, "weekNumber": 20, "date": "2026-05-12", "studentId": 13, "studentName": "許睿桓", "method": "interview", "teacherShare": "目前在學校自主用餐的情況還是比較較難獨立自主坐在椅子上好好用完一頓飯，但是還在持續引導中希望會越來越進步", "parentFeedback": "目前在家裡自主用餐時也和在學校的情況一樣會自己擅自離開椅子上，偶爾也會用手抓飯，希望像老師說的一樣持續引導會越來越進步喔", "createdBy": 1590028}, {"id": 1740014, "weekNumber": 20, "date": "2026-05-12", "studentId": 14, "studentName": "蘇彥澄", "method": "interview", "teacherShare": "目前有觀察到小朋友對於戶外活動的課程喜愛程度非常的高，很高興小朋友都能自主探索和找到自己新奇的玩法", "parentFeedback": "謝謝老師們用心的讓小朋友增加戶外活動的時間，小朋友能夠在上課時間出去外面曬曬太陽對身體一定很好心情也會更加美麗", "createdBy": 1590028}, {"id": 1740015, "weekNumber": 20, "date": "2026-05-12", "studentId": 15, "studentName": "李澪", "method": "interview", "teacherShare": "目前有增加戶外活動的時間，希望小朋友的身體狀況也能夠越來越好", "parentFeedback": "目前在假日的時候也都會盡可能地讓小孩子從事戶外活動，希望多曬曬太陽的情況下感冒會越來越好喔", "createdBy": 1590028}, {"id": 1740016, "weekNumber": 20, "date": "2026-05-12", "studentId": 16, "studentName": "余承澔", "method": "interview", "teacherShare": "目前在配合老師的指令時，偶爾會感到有些迷惘，但是分開式的解釋，小朋友都能夠如實做到非常的棒", "parentFeedback": "目前在家裡也有觀察到小朋友可以依照媽媽說的指令好好的完成每一件事情，偶爾遇到比較聽不懂的情況有依照老師們的建議去做分開式的引導就能成功喔", "createdBy": 1590028}, {"id": 1740017, "weekNumber": 20, "date": "2026-05-12", "studentId": 17, "studentName": "陳禹澔", "method": "interview", "teacherShare": "目前有觀察到小朋友最近比較情緒複雜一些，但經過老師們的擁抱與安撫之下都能能夠恢復平穩的情緒", "parentFeedback": "目前在家裡也有發現比較黏人，情緒也比較容易有出現高低起伏的情況，再請老師多多協助與引導謝謝老師們的用心", "createdBy": 1590028}, {"id": 1740018, "weekNumber": 20, "date": "2026-05-12", "studentId": 18, "studentName": "彭翊宸", "method": "interview", "teacherShare": "目前回學校時和同學相處上都非常的開心，可能是因為上一週都請假生病在家的關係，這週看到老師們非常的開心衝向前面擁抱老師", "parentFeedback": "謝謝老師們都能那麼的愛我們家的小朋友，相信小朋友也非常開心能見到老師和同學們喔", "createdBy": 1590028}, {"id": 1740019, "weekNumber": 20, "date": "2026-05-12", "studentId": 19, "studentName": "林冠邦", "method": "interview", "teacherShare": "目前在學校有越來越進步，如果不小心想要踏出教室的門的時候都能夠依照老師的指令在自己走回來", "parentFeedback": "謝謝老師們這麼用心的引導我們家的小孩，在家裡有頑皮的情況時，爸爸偶爾會嚴厲了一些，但經過老師們的建議後我們會慢慢地引導多給一些愛的鼓勵喔", "createdBy": 1590028}, {"id": 1740020, "weekNumber": 20, "date": "2026-05-12", "studentId": 20, "studentName": "蔡禾悅", "method": "interview", "teacherShare": "目前在做戶外活動時都能夠好好的享受陽光和大家一起做互動，希望會越來越進步", "parentFeedback": "謝謝老師們一直這麼努力觀察我們家小孩的情況也都會在第一時間和媽媽做聯繫以及給予最適當的建議，辛苦你們了", "createdBy": 1590028}, {"id": 1770001, "weekNumber": 20, "date": "2026-05-11", "studentId": 35, "studentName": "賴時儀", "method": "interview", "teacherShare": "好的！沒事的唷~~老師在事發的當天，有致電告知同學家長，同學家長說沒關係的，小朋友在一起玩時，難免會有爭吵，老師跟粿的媽咪都辛苦了！", "parentFeedback": "粿皮蛋咬了同學，再麻煩老師代及向同學家長致歉，謝謝😓😓😓\n\n在家幫她刷牙的時候發現裡面有長小牙齒，真的是真的很癢...", "createdBy": 1440078}, {"id": 1770002, "weekNumber": 20, "date": "2026-05-12", "studentId": 26, "studentName": "林逸宸", "method": "interview", "teacherShare": "逸宸似乎不太喜歡穿長褲，或者說因為太熱不舒服的關係，都會把褲子給蹭掉，如果可以！看看家裡有沒有逸宸的七分褲或短褲，老師會依天氣狀況幫逸宸增減衣物...", "parentFeedback": "好的，媽咪找看看！到時候再帶去中心給逸宸穿，老師辛苦了", "createdBy": 1440078}, {"id": 1770003, "weekNumber": 20, "date": "2026-05-11", "studentId": 25, "studentName": "黃映澄", "method": "interview", "teacherShare": "澄澄最近還是會有咬人的情況，有時也會突然就大叫，老師有努力的在引導她，盡量讓她穩定情緒後，和同學一起玩！再麻煩家長一起留意，謝謝", "parentFeedback": "好的，媽咪在家也有在引導澄澄這樣的行為是不對的，辛苦老師了！", "createdBy": 1440078}, {"id": 1800001, "weekNumber": 20, "date": "2026-05-14", "studentId": 21, "studentName": "劉瑀彤", "method": "interview", "teacherShare": "最近瑀彤很喜歡叫同學跟她一起玩，如果同學沒有順她意，他還會假裝生氣給同學看，這時候同學就會默默的放下玩具，走去跟她一起玩，太搞笑了啦😂", "parentFeedback": "沒辦法！誰叫她就是名副其實的里長母仔，一定要號召大家這樣xd", "createdBy": 1440078}, {"id": 1830001, "weekNumber": 20, "date": "2026-05-14", "studentId": 22, "studentName": "張瑾馨", "method": "interview", "teacherShare": "瑾馨越來越愛撒嬌了耶，每天都一定會緊緊的抱著老師，抱完還會自己走到老師後面，趴在老師身上說揹揹，老師跟她互動說幫老師按摩按摩！哇塞~~瑾馨真的會欸，力道拿捏的剛好，看來可以訓練瑾馨在家也幫辛苦的爸爸媽媽按摩按摩了，呵呵", "parentFeedback": "哇塞！瑾馨在家能這麼乖巧聽話的話，爸爸媽媽就很欣慰了，哈哈", "createdBy": 1440078}, {"id": 1860001, "weekNumber": 20, "date": "2026-05-14", "studentId": 23, "studentName": "余硯宸", "method": "interview", "teacherShare": "硯宸現在每天都會要老師放（伊呀唷）給他聽，嘴上不忘的提醒老師要放對歌，放錯的話硯宸會用手指著老師說，伊呀唷伊呀唷！糟啦...老師最近可能就都得一直循環放著伊呀唷，直到硯宸學聽膩了才能停止了，呵呵", "parentFeedback": "哈哈！硯宸在家也一直吵著要聽伊呀唷，期待他快快學會唱起來，這樣就可以換別首歌了，辛苦老師了xd", "createdBy": 1440078}, {"id": 1890001, "weekNumber": 20, "date": "2026-05-13", "studentId": 30, "studentName": "陳杏恩", "method": "interview", "teacherShare": "杏恩在中心吃飯食慾不錯！進食速度良好，請爸爸幫杏恩帶中心提供的不鏽鋼湯匙，讓他跟同學們用一樣的湯匙，以便融入團體生活。", "parentFeedback": "好的，明天帶；他在家晚上吃飯都會有情緒，吃到後來會不太願意吃。", "createdBy": 750001}, {"id": 1920001, "weekNumber": 20, "date": "2026-05-13", "studentId": 32, "studentName": "吳允霏", "method": "interview", "teacherShare": "允霏最近副食品吃得不錯！所以想把他中午原本喝奶那餐，調整成為吃副食品，讓他在中心三餐都吃副食品，讓他多咀嚼。", "parentFeedback": "好的，再麻煩老師。", "createdBy": 750001}, {"id": 1950001, "weekNumber": 20, "date": "2026-05-14", "studentId": 33, "studentName": "黃語則", "method": "interview", "teacherShare": "則則的口水巾和手帕沒了，明日請幫則則準備；則則的活力很好，頭及胸部都抬得非常高，趴著時會一直移動，想拿前方的玩具。", "parentFeedback": "明日再帶過來；對，他在家也是。", "createdBy": 750001}, {"id": 1980001, "weekNumber": 20, "date": "2026-05-14", "studentId": 30001, "studentName": "黃梓芸", "method": "interview", "teacherShare": "老師今日有幫梓芸按摩肚子，有大便了；下周起，想讓寶貝開始嘗試副食品，副食品纖維較多，可促進腸胃蠕動，如果要開始吃副食品，請帶矽膠湯匙及餐兜。", "parentFeedback": "終於大便了，兩天沒有大便了；可以讓他開始嘗試副食品，在家我們只有自己煮白粥。", "createdBy": 750001}, {"id": 2010001, "weekNumber": 20, "date": "2026-05-15", "studentId": 34, "studentName": "張語恩", "method": "interview", "teacherShare": "打疫苗後，體溫正常，精神活力也都很好；吃副食品時都吃得很好，能接受各種綠色菜，但若進食時，想睡覺就會吃較少。", "parentFeedback": "謝謝老師；回家也是想睡覺時，就不想吃。", "createdBy": 750001}, {"id": 2040001, "weekNumber": 20, "date": "2026-05-16", "studentId": 60001, "studentName": "高士鵬", "method": "interview", "teacherShare": "今日消防演練，老師介紹滅火器、救護車、消防車，鵬鵬很專注地看著老師說明；另外，也喜歡跟老師玩躲貓貓。", "parentFeedback": "認真聽講及愛閱讀，這個有像爸爸；在家洗完澡媽咪用浴巾跟他玩躲貓貓，他都會笑得很開心！", "createdBy": 750001}, {"id": 2070001, "weekNumber": 20, "date": "2026-05-15", "studentId": 24, "studentName": "蔡雨彤", "method": "interview", "teacherShare": "雨彤實在太可愛了，只要老師在幫她換尿布的時候，兩顆眼睛都會對著老師瞪得大大的，這時候老師跟雨彤對到眼的那瞬間，師生2人不約而同的笑了，太有趣的互動了😂", "parentFeedback": "哇~換個尿布也能讓雨彤這麼開心，老師辛苦啦", "createdBy": 1440078}, {"id": 2100001, "weekNumber": 20, "date": "2026-05-15", "studentId": 90001, "studentName": "陳語湉", "method": "interview", "teacherShare": "大福真的是個超級愛笑的寶寶欸，不管老師在做什麼事情，只要跟她對到眼的當下，她總是笑瞇瞇的，甚至與她互動的過程中，她的笑聲真的是會影響到大家，同學聽到她在笑，也會一起笑，每天在中心都過得好快樂呀❤️❤️", "parentFeedback": "大福從小就很喜歡笑，在家也常常對著家人笑，笑容真的很療癒~ 看來大福很喜歡老師跟同學唷，真棒☺️", "createdBy": 1440078}, {"id": 2100002, "weekNumber": 20, "date": "2026-05-15", "studentId": 28, "studentName": "陳品叡", "method": "interview", "teacherShare": "可樂最近會找老師撒嬌，有時候還會因為沒有要到老師抱抱生氣氣，老師一抱起他就笑得好開心，太有趣啦", "parentFeedback": "哈哈，辛苦老師了", "createdBy": 1440078}, {"id": 2130001, "weekNumber": 20, "date": "2026-05-15", "studentId": 29, "studentName": "林禹順", "method": "interview", "teacherShare": "順順真的越大越可愛耶，每次只要有吃飽飽，睡飽飽之後，心情特別好，會自己跑來跟老師撒嬌，笑的時候眼睛也跟著笑，有時候靜靜的看著順順，都會有一種莫名的感動~~", "parentFeedback": "媽咪也有這種感覺，小孩一天一天的在長大，都會讓媽咪覺得順順真的長大了不少，謝謝老師的照顧，辛苦了", "createdBy": 1440078}, {"id": 2160001, "weekNumber": 20, "date": "2026-05-15", "studentId": 1, "studentName": "林品逸", "method": "interview", "teacherShare": "品逸今天對著老師大叫了！老師有提醒他不可以這樣，也有和他慢慢的溝通說要好好的說，不然同學們也會嚇到。", "parentFeedback": "再麻煩老師了，他真的是越來越講不聽，回家後我也會多多跟他溝通的。", "createdBy": 390021}, {"id": 2160002, "weekNumber": 20, "date": "2026-05-15", "studentId": 2, "studentName": "洪明樂", "method": "interview", "teacherShare": "明樂真的是班上的大哥哥了，也很暖呢！看到同學需要幫忙都會幫忙，雖然有時候還是會皮蛋一下，但還是很可愛喔！", "parentFeedback": "謝謝老師，有時候在家也是，活力滿滿，都不睡覺，真傷腦筋😂😂😂", "createdBy": 390021}, {"id": 2160003, "weekNumber": 20, "date": "2026-05-15", "studentId": 3, "studentName": "張蘊桐", "method": "interview", "teacherShare": "蘊桐的分享慾大爆發，每天來學校都和老師聊不停，會分享在家裡做了什麼，幫忙了什麼，真是可愛。", "parentFeedback": "真的！每天回家也都在分享學校的事情，還會說誰誰誰很晚回家什麼的，有時候媽媽都聊到想睡覺了她都還不想睡😂😂", "createdBy": 390021}, {"id": 2160004, "weekNumber": 20, "date": "2026-05-15", "studentId": 4, "studentName": "李芊樂", "method": "phone", "teacherShare": "芊樂感冒的狀況改善很多喔！吃藥真的有效！今天在中心也有排便了喔，媽咪放心，老師會持續觀察的！", "parentFeedback": "謝謝老師，現在的病毒真的好可怕，姐姐在家也都被傳染⋯⋯辛苦老師了！", "createdBy": 390021}, {"id": 2160005, "weekNumber": 20, "date": "2026-05-15", "studentId": 5, "studentName": "黃予希", "method": "interview", "teacherShare": "予希只要一喝水尿布就會蠻滿的，所以老師都有持續的留意她尿布的狀況喔！也會跟他說尿尿了要和老師說！", "parentFeedback": "謝謝老師，有時候上班來不及會沒有幫她換到尿布，辛苦了老師！", "createdBy": 390021}, {"id": 2160006, "weekNumber": 20, "date": "2026-05-15", "studentId": 6, "studentName": "吳允希", "method": "interview", "teacherShare": "允希感冒的狀況有改善囉！不過中午的食慾還是不大好，但除了食欲不大好外，其他都很好喔！活力都還不錯，也會和同學聊天喔！", "parentFeedback": "謝謝老師，我們回家也會再多觀察的，她感冒的這幾天在家也是都不太吃飯，就說想去睡覺了⋯⋯", "createdBy": 390021}, {"id": 2160007, "weekNumber": 20, "date": "2026-05-15", "studentId": 7, "studentName": "楊曜任", "method": "interview", "teacherShare": "曜任越來越會表達自己上廁所了，雖然有時候會講錯，但大便的時候都不會講錯喔！繼續努力吧！", "parentFeedback": "謝謝老師，辛苦了！看到曜任進步真的很開心！", "createdBy": 390021}, {"id": 2160008, "weekNumber": 20, "date": "2026-05-15", "studentId": 8, "studentName": "莊又羽", "method": "interview", "teacherShare": "最近又羽的語言發展進步的很快喔！老師說什麼他就跟著說什麼，而且非常清楚喔！", "parentFeedback": "在家都不太愛說話，都只說兩個字的，我們會再多多引導她的！", "createdBy": 390021}, {"id": 2160009, "weekNumber": 20, "date": "2026-05-15", "studentId": 9, "studentName": "王鈺棠", "method": "interview", "teacherShare": "棠棠真的不太愛喝水，拿著水壺但其實都沒有喝進去，老師會多多提醒他的！", "parentFeedback": "老師辛苦了，棠棠在家裡也是都不太愛喝，請他喝還會生氣呢！", "createdBy": 390021}, {"id": 2160010, "weekNumber": 20, "date": "2026-05-15", "studentId": 10, "studentName": "吳承諺", "method": "interview", "teacherShare": "諺諺在學校超級活潑，有時候都坐不住，不過老師們都會慢慢的和他溝通，提醒他要坐好喔！", "parentFeedback": "在家裡也是，都跟著哥哥到處亂跑，講都講不聽，辛苦老師了！", "createdBy": 390021}, {"id": 2160011, "weekNumber": 20, "date": "2026-05-15", "studentId": 27, "studentName": "謝知愛", "method": "interview", "teacherShare": "知愛現在慢慢地會放開手獨站好幾秒了！有時候也會走個一兩步，期待他會走路的那天！", "parentFeedback": "知愛好棒，要多多加油喔！", "createdBy": 390021}, {"id": 2190001, "weekNumber": 21, "date": "2026-05-21", "studentId": 25, "studentName": "黃映澄", "method": "interview", "teacherShare": "在學校早餐都給兩到三塊的麵包，午餐跟點心都是給澄滿滿的一碗，目前沒有聽到澄開口說還要，老師再協助媽咪觀察幾天看看，於聯絡簿上回覆給媽咪唷", "parentFeedback": "澄最近半夜會起來說要喝奶奶，在學校有沒有想要吃比較多或是還餓要加飯量的感覺呢？", "createdBy": 1440078}, {"id": 2220001, "weekNumber": 21, "date": "2026-05-21", "studentId": 29, "studentName": "林禹順", "method": "interview", "teacherShare": "好的，沒有問題唷！除了吸管式奶瓶之外，老師也在努力的引導順順自己拿著水壺練習喝水唷~順順拿得很穩，持續練習中！！", "parentFeedback": "順順平常在家已在使用吸管式奶瓶用餐，因此今日開始改帶同款奶瓶至學校，再請老師留意順順在校的使用情況，謝謝", "createdBy": 1440078}, {"id": 2250001, "weekNumber": 21, "date": "2026-05-21", "studentId": 30, "studentName": "陳杏恩", "method": "interview", "teacherShare": "今日午休起床後有便便，便量又加上有尿尿，有溢出弄髒褲子與床罩，再請爸爸明天幫他準備床罩。這兩日在中心吃飯沒有在家中嘔吐情形，便便次數有較多，但精神活力食慾都很好！", "parentFeedback": "好的，謝謝！不知是否尿布太小？還是不適合？是否要換尿布，因為最近這週比較常炸屎；杏恩下周一（5/25）要出去玩，請假一日。", "createdBy": 750001}, {"id": 2280001, "weekNumber": 21, "date": "2026-05-21", "studentId": 32, "studentName": "吳允霏", "method": "interview", "teacherShare": "霏霏最近非常喜歡扶站，且會稍微左右移動；依舊非常喜歡說爸爸媽媽；再麻煩媽媽幫他剪指甲，怕他抓傷自己；目前三餐吃副食吃得不錯，他改用不鏽鋼湯匙後，吃飯有比較快，因為在中心無喝奶，今日讓他帶回奶粉。", "parentFeedback": "好的，謝謝老師！會再幫他修剪指甲；家中剛好也沒奶粉，帶回家泡。", "createdBy": 750001}, {"id": 2310001, "weekNumber": 21, "date": "2026-05-21", "studentId": 33, "studentName": "黃語則", "method": "interview", "teacherShare": "最近的則則很喜歡把胸部及屁股抬起來，很像在做伏地挺身，很可愛！今日則則口腔檢查時，有點小情緒，躺平後一直踢動他的雙腳，老師及醫護人員安撫後，有順利完成檢查！", "parentFeedback": "對，他在家也會撐起來！可愛的則則！不知他是不是要長牙了？", "createdBy": 750001}, {"id": 2340001, "weekNumber": 21, "date": "2026-05-22", "studentId": 30001, "studentName": "黃梓芸", "method": "interview", "teacherShare": "梓芸的副食品吃的很好，都願意開口吞嚥；他的會陰部紅，吃副食品後，一日便便二到三次，又很喜歡趴著轉動360度，且皮膚較敏感；老師幫他勤換尿布，一小時換一次，特別留意有無便便，加強清潔，都有擦屁屁膏，沒有便便時，有比較不紅，但下午便便兩次加尿尿又馬上紅，再請家長回家後也留意。", "parentFeedback": "了解，昨天回家時會陰部很紅！今日不知有沒有好點？他在家副食吃得不好，都會不吃吐出來，但是因為我們只有煮白粥，沒像中心有加高麗菜和紅蘿蔔。", "createdBy": 750001}, {"id": 2370001, "weekNumber": 21, "date": "2026-05-21", "studentId": 34, "studentName": "張語恩", "method": "interview", "teacherShare": "今日口腔檢查，語恩非常勇敢，檢查過程情緒都很穩定！他副食品也吃得很好，在中心能自己入睡，天使寶寶。", "parentFeedback": "謝謝！他在家沒有這麼乖！副食品吃幾口就會有情緒，不願意吃，睡覺也要人家哄睡！", "createdBy": 750001}, {"id": 2400001, "weekNumber": 21, "date": "2026-05-24", "studentId": 60001, "studentName": "高士鵬", "method": "interview", "teacherShare": "今日口腔檢查，醫師很喜歡鵬鵬，他情緒平穩地讓醫師檢查，表現很棒！勇敢的小寶貝！", "parentFeedback": "謝謝醫師，請問鵬沒有牙齒，那口腔檢查重點是會放在哪？鵬在學校越來越進步！最近回家都沒有什麼哭鬧，情緒都比以前更穩定，謝謝老師！", "createdBy": 750001}, {"id": 2430001, "weekNumber": 21, "date": "2026-05-21", "studentId": 21, "studentName": "劉瑀彤", "method": "interview", "teacherShare": "今天看牙醫塗氟，瑀彤好勇敢，全程淡定完成，但嘴唇有比較乾，再請家長留意", "parentFeedback": "這麼棒！平常在診所的時候都不是這樣...\n好的，謝謝老師", "createdBy": 1440078}, {"id": 2430002, "weekNumber": 21, "date": "2026-05-21", "studentId": 22, "studentName": "張瑾馨", "method": "interview", "teacherShare": "今天看牙醫塗氟，瑾馨雖然有點害怕而抗拒，但最後還是很勇敢的給醫生塗氟唷，超棒的", "parentFeedback": "謝謝老師，謝謝醫生", "createdBy": 1440078}, {"id": 2430003, "weekNumber": 21, "date": "2026-05-21", "studentId": 23, "studentName": "余硯宸", "method": "interview", "teacherShare": "今天給牙醫口檢，硯宸雖然放聲大哭，但最後有順利完成唷，很棒", "parentFeedback": "哭聲應該沒有嚇到醫生吧xd \n辛苦老師跟醫生囉", "createdBy": 1440078}, {"id": 2460001, "weekNumber": 21, "date": "2026-05-21", "studentId": 24, "studentName": "蔡雨彤", "method": "interview", "teacherShare": "今天看牙醫塗氟，雨彤哭慘了，嘴巴張到超大，哈哈..但還是有順利完成唷，很棒！\n醫生有表示雨彤奶嘴吃很兇，建議慢慢戒掉", "parentFeedback": "好的，謝謝老師", "createdBy": 1440078}, {"id": 2460003, "weekNumber": 21, "date": "2026-05-21", "studentId": 35, "studentName": "賴時儀", "method": "interview", "teacherShare": "今天看牙醫塗氟，時儀太有趣了，一開場就直接先哭爆，結束後立馬起身要老師趕快抱她離開現場，哈哈", "parentFeedback": "哈哈，時儀偶包太重了！辛苦老師跟醫生了", "createdBy": 1440078}, {"id": 2460004, "weekNumber": 21, "date": "2026-05-21", "studentId": 90001, "studentName": "陳語湉", "method": "interview", "teacherShare": "今天看牙醫口檢，湉湉很棒喔，嘴巴張很大的給醫生做檢查，雖然有點害怕，但湉湉還是很勇敢的完成唷，很棒", "parentFeedback": "湉湉蠻喜歡挑戰新鮮事，唯獨牙醫這關還有點偶包過重，哈哈！老師辛苦了", "createdBy": 1440078}, {"id": 2460005, "weekNumber": 21, "date": "2026-05-21", "studentId": 26, "studentName": "林逸宸", "method": "interview", "teacherShare": "今天看牙醫塗氟，逸宸很有趣，一開始很淡定哦，表現很棒~~但一躺下的瞬間，直接破防，放聲大哭，哈哈！不過最後還是有順利完成，很棒", "parentFeedback": "哎呀！真是辛苦老師跟醫生啦xd", "createdBy": 1440078}, {"id": 2460006, "weekNumber": 21, "date": "2026-05-21", "studentId": 28, "studentName": "陳品叡", "method": "interview", "teacherShare": "今天看牙醫塗氟，可樂很棒喔！嘴巴張很大，醫生也有表揚可樂四顆門牙都長好了，耶~", "parentFeedback": "開心開心，謝謝老師跟醫生", "createdBy": 1440078}, {"id": 2490001, "weekNumber": 22, "date": "2026-05-25", "studentId": 90001, "studentName": "陳語湉", "method": "interview", "teacherShare": "大福在中心戒奶嘴有兩、三天了，在戒奶嘴午睡的同時，難免會沒有安全感，無法適應的過渡期！前兩天時好時壞，今天老師拍睡加唱小星星給大福聽，大福聽著聽著就睡著了，一路睡到午睡時間到，超棒的！我們一起加油，幫助大福戒奶嘴成功💪💪💪", "parentFeedback": "哇~謝謝老師，情緒價值給好滿！媽媽在家也是唱小星星給大福聽xd   希望大福可以順利成功戒掉奶嘴💪💪💪", "createdBy": 1440078}, {"id": 2520001, "weekNumber": 22, "date": "2026-05-25", "studentId": 26, "studentName": "林逸宸", "method": "interview", "teacherShare": "最近天氣比較炎熱，室內溫度會保持25.26度，有觀察到逸宸若穿著外套活動時會太熱，想跟爸爸媽媽討論看看能否在活動時間看狀況幫逸宸增減衣物，放學前再幫逸宸穿上..", "parentFeedback": "可以的唷，因為先前逸宸常感冒，怕一直都不會好，再麻煩老師依照逸宸的狀況，增減衣物，謝謝老師", "createdBy": 1440078}, {"id": 2550001, "weekNumber": 22, "date": "2026-05-26", "studentId": 29, "studentName": "林禹順", "method": "interview", "teacherShare": "好的，沒問題！媽咪辛苦了", "parentFeedback": "順順臉上過敏長了疹子，醫生建議近日先別到戶外接觸到空污，花粉，以免疹子發紅惡化！再請老師協助留意，謝謝！", "createdBy": 1440078}, {"id": 2580001, "weekNumber": 22, "date": "2026-05-26", "studentId": 28, "studentName": "陳品叡", "method": "interview", "teacherShare": "好的，沒問題喔，辛苦媽咪了", "parentFeedback": "可樂常大軟便，再請老師多留意，謝謝！", "createdBy": 1440078}];
const INCIDENTS = [{"id": 1, "date": "2026-02-26", "className": "O", "studentId": 27, "studentName": "謝知愛", "description": "被婕老師撞到彈出去", "woundType": "", "time": "22:21", "location": "教室", "parentResponse": "媽媽說沒關係，知愛最愛老師了", "handler": "", "trackingStatus": "觀察中", "createdBy": 1}, {"id": 60001, "date": "2026-03-04", "className": "C", "studentId": 14, "studentName": "蘇彥澄", "description": "玩鼓的教具時，走路跌倒不小心撞到嘴巴上嘴唇內側", "woundType": "bump", "time": "10:36", "location": "教室", "parentResponse": "已了解情況，協助觀察下午情形", "handler": "黎又瑄", "trackingStatus": "觀察中", "createdBy": 1590028}, {"id": 90001, "date": "2026-03-09", "className": "C", "studentId": 11, "studentName": "葉紫婕", "description": "玩遊戲時被東西用到", "woundType": "刮傷", "time": "15:44", "location": "教室", "parentResponse": "回家護理可理解", "handler": "黎又瑄", "trackingStatus": "觀察中", "createdBy": 1590028}, {"id": 120001, "date": "2026-03-11", "className": "C", "studentId": 14, "studentName": "蘇彥澄", "description": "跟隔壁床同學玩得很開心，不小心被指甲抓到", "woundType": "抓傷", "time": "16:20", "location": "教室", "parentResponse": "可以理解和同學愉快玩耍之中不小心抓傷的情況", "handler": "黎又瑄", "trackingStatus": "已處理", "createdBy": 1590028}, {"id": 150001, "date": "2026-03-12", "className": "C", "studentId": 12, "studentName": "陳奕睿", "description": "自己咬到下嘴唇", "woundType": "bite", "time": "15:00", "location": "教室", "parentResponse": "沒關係，可以理解", "handler": "黎又瑄", "trackingStatus": "已處理", "createdBy": 1590028}, {"id": 180001, "date": "2026-03-12", "className": "I", "studentId": 30001, "studentName": "黃梓芸", "description": "玩教具太開心！自己的手指甲揮到右側眉毛上方導致一條紅痕。", "woundType": "抓傷", "time": "12:55", "location": "教室", "parentResponse": "了解，他在家有時也會揮到。", "handler": "蘇榆婷", "trackingStatus": "已處理", "createdBy": 750001}, {"id": 210001, "date": "2026-03-17", "className": "C", "studentId": 14, "studentName": "蘇彥澄", "description": "自己走路時不小心跌倒咬到嘴唇內側", "woundType": "bite", "time": "10:03", "location": "教室", "parentResponse": "觀察傷口狀況及牙齒狀況，目前可理解", "handler": "黎又瑄", "trackingStatus": "觀察中", "createdBy": 1590028}, {"id": 210002, "date": "2026-03-17", "className": "C", "studentId": 19, "studentName": "林冠邦", "description": "在床內沒扶好，不小心跌倒", "woundType": "bump", "time": "16:05", "location": "教室", "parentResponse": "可理解，協助護理", "handler": "黎又瑄", "trackingStatus": "已處理", "createdBy": 1590028}, {"id": 240001, "date": "2026-03-17", "className": "C", "studentId": 16, "studentName": "余承澔", "description": "走路自己跌倒，撞到額頭有紅印", "woundType": "bump", "time": "17:20", "location": "大廳", "parentResponse": "媽咪可理解，已告知有冰敷處理", "handler": "黎又瑄", "trackingStatus": "已處理", "createdBy": 1590028}, {"id": 270001, "date": "2026-03-19", "className": "C", "studentId": 17, "studentName": "陳禹澔", "description": "在床內玩得太興奮，點頭時咬到自己的下唇內側", "woundType": "bite", "time": "15:30", "location": "教室", "parentResponse": "可明白，持續護理", "handler": "黎又瑄", "trackingStatus": "觀察中", "createdBy": 1590028}, {"id": 300001, "date": "2026-03-24", "className": "C", "studentId": 11, "studentName": "葉紫婕", "description": "走路不小心跌倒撞到，微微紅印在右耳朵", "woundType": "bump", "time": "16:45", "location": "教室", "parentResponse": "可理解", "handler": "黎又瑄", "trackingStatus": "已處理", "createdBy": 1590028}, {"id": 330001, "date": "2026-03-27", "className": "C", "studentId": 12, "studentName": "陳奕睿", "description": "拿著奶瓶沒站穩撞到床欄邊，唇繫帶旁有傷口，已冰敷處理", "woundType": "bump", "time": "16:12", "location": "教室", "parentResponse": "目前了解情況，回家會接續觀察情況", "handler": "黎又瑄", "trackingStatus": "觀察中", "createdBy": 1590028}, {"id": 360001, "date": "2026-03-30", "className": "C", "studentId": 11, "studentName": "葉紫婕", "description": "拿教具時不慎跌倒，教具撞到右上排牙齦有兩處小傷口，已加壓止血", "woundType": "bump", "time": "10:33", "location": "大廳", "parentResponse": "可理解", "handler": "黎又瑄", "trackingStatus": "已處理", "createdBy": 1590028}, {"id": 390001, "date": "2026-04-02", "className": "C", "studentId": 14, "studentName": "蘇彥澄", "description": "走路跌倒撞到右額頭，已冰敷處理", "woundType": "bump", "time": "10:03", "location": "圖書區", "parentResponse": "可以了解，回家也會多留意", "handler": "黎又瑄", "trackingStatus": "觀察中", "createdBy": 1590028}, {"id": 420001, "date": "2026-04-02", "className": "I", "studentId": 33, "studentName": "黃語則", "description": "吃早餐完後坐在安撫椅時，太興奮開心，抓自己的左前額上方，被自己指甲刮傷。", "woundType": "抓傷", "time": "08:45", "location": "教室", "parentResponse": "好的，再麻煩老師了。", "handler": "蘇榆婷", "trackingStatus": "已處理", "createdBy": 750001}, {"id": 450001, "date": "2026-04-10", "className": "C", "studentId": 12, "studentName": "陳奕睿", "description": "床上走路沒走好，下巴撞到床欄，牙齒咬到左側上方口腔內側，已加壓止血", "woundType": "bite", "time": "15:18", "location": "教室", "parentResponse": "已了解情況", "handler": "黎又瑄", "trackingStatus": "已處理", "createdBy": 1590028}, {"id": 480001, "date": "2026-04-10", "className": "C", "studentId": 16, "studentName": "余承澔", "description": "走路沒走好，撞到椅子，左額頭上方瘀青，冰敷處理", "woundType": "bump", "time": "14:40", "location": "教室", "parentResponse": "可以了解", "handler": "黎又瑄", "trackingStatus": "已處理", "createdBy": 1590028}, {"id": 510001, "date": "2026-04-16", "className": "A", "studentId": 22, "studentName": "張瑾馨", "description": "遊戲時間有同學想搶瑾馨的位子，被瑾馨伸手阻止，同學搶不過直接咬人。", "woundType": "bite", "time": "10:22", "location": "教室", "parentResponse": "表示了解", "handler": "詹芳婕", "trackingStatus": "已處理", "createdBy": 390052}, {"id": 540001, "date": "2026-04-17", "className": "I", "studentId": 30001, "studentName": "黃梓芸", "description": "想睡覺又想喝奶，老師幫他戴上手套後，他喝完奶後，老師發現頭頂有兩個紅痕，可能是想喝奶又想睡覺時，揮動手抓傷自己的左側頭頂。", "woundType": "抓傷", "time": "16:00", "location": "教室", "parentResponse": "了解，在家也會這樣。", "handler": "蘇榆婷", "trackingStatus": "已處理", "createdBy": 750001}, {"id": 570001, "date": "2026-04-21", "className": "I", "studentId": 30001, "studentName": "黃梓芸", "description": "睡醒後，自己想翻身翻不過去有點小情緒，又剛好小手套太鬆脫落了，手手抓傷自己的左側頭頂多處紅痕。", "woundType": "抓傷", "time": "15:00", "location": "教室", "parentResponse": "好的。", "handler": "蘇榆婷", "trackingStatus": "已處理", "createdBy": 750001}, {"id": 570002, "date": "2026-04-21", "className": "I", "studentId": 33, "studentName": "黃語則", "description": "他想喝奶，手有揮頭部，有點小情緒，老師餵奶後發現他額頭上方中間處及右側頭部有抓痕，也可能是玩教具時太興奮抓的。", "woundType": "抓傷", "time": "16:25", "location": "教室", "parentResponse": "再麻煩老師了", "handler": "蘇榆婷", "trackingStatus": "已處理", "createdBy": 750001}, {"id": 600001, "date": "2026-04-22", "className": "C", "studentId": 14, "studentName": "蘇彥澄", "description": "玩教具時不小心撞到", "woundType": "bump", "time": "10:15", "location": "大廳", "parentResponse": "可理解", "handler": "黎又瑄", "trackingStatus": "已處理", "createdBy": 1590028}, {"id": 600002, "date": "2026-04-22", "className": "A", "studentId": 26, "studentName": "林逸宸", "description": "在床裡準備睡覺往前趴撞到床欄。", "woundType": "scrape", "time": "11:40", "location": "教室", "parentResponse": "表示了解並請老師觀察狀況", "handler": "詹芳婕", "trackingStatus": "觀察中", "createdBy": 390052}, {"id": 630001, "date": "2026-04-23", "className": "I", "studentId": 30001, "studentName": "黃梓芸", "description": "趴著時自己雙腳踢踢時，自己左腳的腳趾甲刮傷了右腳小腿後方及右腳踝外側。", "woundType": "刮傷", "time": "14:20", "location": "教室", "parentResponse": "家長接送時說左腳大拇指腳指甲有點微裂,可能真的會刮傷自己的腿。", "handler": "蘇榆婷", "trackingStatus": "已處理", "createdBy": 750001}, {"id": 660001, "date": "2026-04-24", "className": "I", "studentId": 30001, "studentName": "黃梓芸", "description": "午休起來，自己把小手套拆掉其中一隻，玩的很開心，手手的指甲抓傷自己左側額頭。", "woundType": "抓傷", "time": "14:40", "location": "教室", "parentResponse": "在家也會拔掉自己的小手套。", "handler": "蘇榆婷", "trackingStatus": "已處理", "createdBy": 750001}, {"id": 690001, "date": "2026-04-28", "className": "A", "studentId": 23, "studentName": "余硯宸", "description": "跟同學在玩具櫃裡往外看小鳥的時候，推擠到同學而被咬", "woundType": "bite", "time": "10:25", "location": "大廳", "parentResponse": "再麻煩老師多留意", "handler": "林心璇", "trackingStatus": "已處理", "createdBy": 1440078}, {"id": 720001, "date": "2026-04-30", "className": "I", "studentId": 30, "studentName": "陳杏恩", "description": "在床上，扶站時，沒有站好撞到左眼眼皮，有瘀青狀況，立即冰敷。", "woundType": "撞傷瘀青", "time": "15:05", "location": "教室", "parentResponse": "了解", "handler": "蘇榆婷", "trackingStatus": "已處理", "createdBy": 750001}, {"id": 750001, "date": "2026-04-24", "className": "C", "studentId": 13, "studentName": "許睿桓", "description": "玩教具時太開心不小心自己用到鼻子下方一個小傷口", "woundType": "bump", "time": "10:15", "location": "大廳", "parentResponse": "可以理解", "handler": "黎又瑄", "trackingStatus": "已處理", "createdBy": 1590028}, {"id": 750002, "date": "2026-04-24", "className": "C", "studentId": 11, "studentName": "葉紫婕", "description": "玩教具時太開心不小心用到下巴", "woundType": "bump", "time": "10:15", "location": "大廳", "parentResponse": "遊戲中受傷很正常，可以理解", "handler": "黎又瑄", "trackingStatus": "已處理", "createdBy": 1590028}, {"id": 750003, "date": "2026-04-30", "className": "C", "studentId": 20, "studentName": "蔡禾悅", "description": "活動中跌倒撞到教具咬到自己下嘴唇", "woundType": "bite", "time": "10:30", "location": "教室", "parentResponse": "可以理解", "handler": "黎又瑄", "trackingStatus": "已處理", "createdBy": 1590028}, {"id": 750004, "date": "2026-04-30", "className": "C", "studentId": 16, "studentName": "余承澔", "description": "自主收玩具時沒有站穩，不小心拿教具盒子壓到左大拇指上方有點破皮", "woundType": "bump", "time": "16:45", "location": "教室", "parentResponse": "沒關係，回家再持續護理即可", "handler": "黎又瑄", "trackingStatus": "觀察中", "createdBy": 1590028}, {"id": 780001, "date": "2026-05-04", "className": "A", "studentId": 24, "studentName": "蔡雨彤", "description": "在床上等待換尿布時，跟隔壁同學開心跳跳跳，不小小撞到床沿而咬到下嘴唇", "woundType": "bite", "time": "09:35", "location": "教室", "parentResponse": "好的，再麻煩老師觀察雨彤今天的狀況，謝謝", "handler": "林心璇", "trackingStatus": "已處理", "createdBy": 1440078}, {"id": 810001, "date": "2026-05-05", "className": "C", "studentId": 12, "studentName": "陳奕睿", "description": "跳舞時左臉頰撞到床欄", "woundType": "bump", "time": "15:55", "location": "教室", "parentResponse": "可以理解", "handler": "黎又瑄", "trackingStatus": "已處理", "createdBy": 1590028}, {"id": 810002, "date": "2026-05-05", "className": "C", "studentId": 14, "studentName": "蘇彥澄", "description": "跳舞時右臉頰撞到", "woundType": "bump", "time": "15:55", "location": "教室", "parentResponse": "可以理解", "handler": "黎又瑄", "trackingStatus": "已處理", "createdBy": 1590028}, {"id": 840001, "date": "2026-05-07", "className": "I", "studentId": 60001, "studentName": "高士鵬", "description": "玩教具太開心，興奮揮動手時，抓到左眼下方。", "woundType": "抓傷", "time": "10:58", "location": "教室", "parentResponse": "看到受傷照片後，媽媽說還好啦，沒事唷！", "handler": "蘇榆婷", "trackingStatus": "已處理", "createdBy": 750001}, {"id": 870001, "date": "2026-05-11", "className": "A", "studentId": 90001, "studentName": "陳語湉", "description": "與同學在互動的時候靠太近，同學以為湉湉要拿她玩具，就咬了湉湉的左臉頰...老師看到立即將同學分開，安撫湉湉情緒並冰敷，湉湉穩定下來後開心等吃飯，午休時間也睡得很好唷！老師後續會持續觀察湉湉受傷部位的恢復狀況，寫於聯絡簿或致電給爸爸媽媽...", "woundType": "bite", "time": "10:35", "location": "圖書區", "parentResponse": "再麻煩老師多多注意班上同學的行為，同時我們也會引導湉湉不能也有此行為，謝謝老師", "handler": "林心璇", "trackingStatus": "已痊癒", "createdBy": 1440078}, {"id": 870002, "date": "2026-05-11", "className": "A", "studentId": 23, "studentName": "余硯宸", "description": "硯宸看到同學把玩具排成了一排產生好奇心，跟想同學一起玩的當下，伸手過去被同學誤以為要搶走玩具而被咬，老師看到立即將兩人分開，安撫硯宸情緒並冰敷，硯宸一下下就穩定下來了，拿著玩具坐在老師身邊玩得很開心...", "woundType": "bite", "time": "16:40", "location": "教室", "parentResponse": "只是這樣伸手就被咬啦？？xd\n再麻煩老師多多照顧硯宸了，謝謝", "handler": "林心璇", "trackingStatus": "已處理", "createdBy": 1440078}, {"id": 900001, "date": "2026-05-18", "className": "C", "studentId": 12, "studentName": "陳奕睿", "description": "玩一玩不慎跌倒咬到自己下嘴唇", "woundType": "bite", "time": "10:10", "location": "教室", "parentResponse": "可理解", "handler": "黎又瑄", "trackingStatus": "已處理", "createdBy": 1590028}, {"id": 900002, "date": "2026-05-18", "className": "C", "studentId": 14, "studentName": "蘇彥澄", "description": "跌倒咬到自己上嘴唇", "woundType": "bite", "time": "16:36", "location": "教室", "parentResponse": "明白持續觀察", "handler": "黎又瑄", "trackingStatus": "觀察中", "createdBy": 1590028}, {"id": 900003, "date": "2026-05-20", "className": "C", "studentId": 17, "studentName": "陳禹澔", "description": "唱大象點頭時咬到自己下嘴唇", "woundType": "bite", "time": "16:37", "location": "教室", "parentResponse": "可理解", "handler": "黎又瑄", "trackingStatus": "已處理", "createdBy": 1590028}, {"id": 930001, "date": "2026-05-20", "className": "C", "studentId": 16, "studentName": "余承澔", "description": "喝光水時，水壺撞到眉心中間，接著跟老師熱情抱抱時，自己磨到床邊紅紅的", "woundType": "bump", "time": "17:00", "location": "教室", "parentResponse": "可理解", "handler": "黎又瑄", "trackingStatus": "已處理", "createdBy": 1590028}];
